--- src/SecureApiManager.Codeunit.al
+++ src/SecureApiManager.Codeunit.al
+codeunit 50100 "Secure Api Manager"
+{
+    Access = Internal;
+
+    [NonDebuggable]
+    internal procedure StoreApiKey(ConfigCode: Code[20]; ApiKey: SecretText)
+    begin
+        IsolatedStorage.SetEncrypted(GetStorageKey(ConfigCode), ApiKey, DataScope::Module);
+    end;
+
+    [NonDebuggable]
+    internal procedure GetApiKey(ConfigCode: Code[20]) Result: SecretText
+    begin
+        if not IsolatedStorage.Contains(GetStorageKey(ConfigCode), DataScope::Module) then
+            Error('API key not configured for %1.', ConfigCode);
+        IsolatedStorage.Get(GetStorageKey(ConfigCode), DataScope::Module, Result);
+    end;
+
+    procedure CallApi(ConfigCode: Code[20])
+    var
+        Client: HttpClient;
+        Headers: HttpHeaders;
+        Response: HttpResponseMessage;
+        AuthHeader: SecretText;
+    begin
+        AuthHeader := SecretStrSubstNo('Bearer %1', GetApiKey(ConfigCode));
+        Headers := Client.DefaultRequestHeaders();
+        Headers.Add('Authorization', AuthHeader);
+
+        if not Client.Get('https://api.businesscentral.dynamics.com/v2.0/data', Response) then
+            Error('Request failed. Check configuration.');
+
+        if not Response.IsSuccessStatusCode then
+            Error('Request failed. Check configuration.');
+    end;
+
+    local procedure GetStorageKey(ConfigCode: Code[20]): Text[50]
+    begin
+        exit('ApiKey_' + ConfigCode);
+    end;
+}
+

--- src/SecureKeyManager.Codeunit.al
+++ src/SecureKeyManager.Codeunit.al
+codeunit 50101 "Secure Key Manager"
+{
+    Access = Internal;
+
+    [NonDebuggable]
+    procedure StoreEncryptedKey(KeyName: Code[20]; KeyValue: SecretText)
+    begin
+        if IsolatedStorage.Contains(KeyName, DataScope::Module) then
+            IsolatedStorage.Delete(KeyName, DataScope::Module);
+
+        IsolatedStorage.SetEncrypted(KeyName, KeyValue, DataScope::Module);
+    end;
+
+    [NonDebuggable]
+    procedure RetrieveKey(KeyName: Code[20]) Result: SecretText
+    begin
+        if not IsolatedStorage.Contains(KeyName, DataScope::Module) then
+            Error('Key not found. Please configure it first.');
+
+        IsolatedStorage.Get(KeyName, DataScope::Module, Result);
+    end;
+
+    procedure HasKey(KeyName: Code[20]): Boolean
+    begin
+        exit(IsolatedStorage.Contains(KeyName, DataScope::Module));
+    end;
+
+    procedure RemoveKey(KeyName: Code[20])
+    begin
+        if IsolatedStorage.Contains(KeyName, DataScope::Module) then
+            IsolatedStorage.Delete(KeyName, DataScope::Module);
+    end;
+}
+

--- src/SafeErrorHandler.Codeunit.al
+++ src/SafeErrorHandler.Codeunit.al
+codeunit 50102 "Safe Error Handler"
+{
+    procedure HandleApiResponse(StatusCode: Integer): Text
+    begin
+        case StatusCode of
+            200, 201:
+                exit('');
+            400:
+                exit('Invalid request. Please check your input.');
+            401:
+                exit('Authentication failed. Please verify your credentials.');
+            403:
+                exit('You do not have permission for this operation.');
+            404:
+                exit('The requested resource was not found.');
+            else
+                exit('An unexpected error occurred. Contact your administrator.');
+        end;
+    end;
+
+    procedure TryPostDocument(DocNo: Code[20]): Boolean
+    var
+        Success: Boolean;
+    begin
+        Success := TryPost(DocNo);
+        if not Success then
+            Error('Could not post document %1. Please review and try again.', DocNo);
+        exit(true);
+    end;
+
+    [TryFunction]
+    local procedure TryPost(DocNo: Code[20])
+    begin
+        // Posting logic here
+    end;
+}
+

