+++ src/SafeRecordQuery.Codeunit.al
+codeunit 50109 "Safe Record Query"
+{
+    procedure FindCustomersByCity(City: Text[30]): Integer
+    var
+        Customer: Record Customer;
+    begin
+        Customer.SetRange(City, City);
+        exit(Customer.Count());
+    end;
+
+    procedure FindOpenSalesOrders(CustNo: Code[20]): Boolean
+    var
+        SalesHeader: Record "Sales Header";
+    begin
+        SalesHeader.SetRange("Document Type", SalesHeader."Document Type"::Order);
+        SalesHeader.SetRange("Sell-to Customer No.", CustNo);
+        SalesHeader.SetFilter(Status, '%1', SalesHeader.Status::Open);
+        exit(SalesHeader.FindSet());
+    end;
+
+    procedure GetItemsAbovePrice(MinPrice: Decimal): Integer
+    var
+        Item: Record Item;
+    begin
+        Item.SetFilter("Unit Price", '>%1', MinPrice);
+        exit(Item.Count());
+    end;
+
+    procedure FindVendorByName(NameFilter: Text[100]): Code[20]
+    var
+        Vendor: Record Vendor;
+    begin
+        Vendor.SetFilter(Name, '@*' + NameFilter + '*');
+        if Vendor.FindFirst() then
+            exit(Vendor."No.");
+        exit('');
+    end;
+}
