--- src/EAEmailSendDispatcher.Codeunit.al
+++ src/EAEmailSendDispatcher.Codeunit.al
+codeunit 50200 "EA Email Send Dispatcher"
+{
+    TableNo = "Email Message";
+
+    var
+        EmailScenario: Enum "Email Scenario";
+        NoEmailRegisteredErr: Label 'No email account is registered for the Expense Agent';
+        EmailFailedErr: Label 'Failed to send email: %1';
+        EmailSentMsg: Label 'Email sent successfully to %1';
+
+    trigger OnRun()
+    var
+        EmailAccount: Record "Email Account";
+        Email: Codeunit Email;
+        EmailMessage: Codeunit "Email Message";
+    begin
+        InitializeEmailSettings();
+
+        if not EmailAccount.FindFirst() then
+            Error(NoEmailRegisteredErr);
+
+        ProcessEmailMessage(Rec, EmailAccount);
+    end;
+
+    procedure SendNotificationEmail(Recipients: List of [Text]; Subject: Text; Body: Text)
+    var
+        EmailAccount: Record "Email Account";
+        Email: Codeunit Email;
+        EmailMessage: Codeunit "Email Message";
+        EmailRecipient: Text;
+        EmailAddress: Text;
+        i: Integer;
+    begin
+        if Recipients.Count = 0 then
+            Error('No recipients specified for notification email.');
+
+        if not EmailAccount.FindFirst() then
+            Error(NoEmailRegisteredErr);
+
+        EmailMessage.Create(Recipients, Subject, Body, true);
+
+        EmailMessage.AddCustomDimension('EmailType', 'Notification');
+        EmailMessage.AddCustomDimension('Source', 'ExpenseAgent');
+        EmailMessage.AddCustomDimension('Timestamp', Format(CurrentDateTime));
+
+        if Email.Send(EmailMessage, EmailAccount."Account Id") then begin
+            for i := 1 to Recipients.Count do begin
+                Recipients.Get(i, EmailRecipient);
+                Message(EmailSentMsg, EmailRecipient);
+            end;
+        end else
+            Error(EmailFailedErr, GetLastErrorText());
+    end;
+
+    local procedure InitializeEmailSettings()
+    var
+        EmailSetup: Record "Email Setup";
+        FeatureManagement: Record "Feature Management";
+    begin
+        if not EmailSetup.Get() then begin
+            EmailSetup.Init();
+            EmailSetup."Enable Email" := true;
+            EmailSetup."Default Scenario" := EmailScenario::"Expense Management";
+            EmailSetup.Insert();
+        end;
+
+        FeatureManagement.SetRange("Feature Key", 'EmailIntegration');
+        if FeatureManagement.FindFirst() then
+            if not FeatureManagement.Enabled then
+                Error('Email integration feature is not enabled.');
+    end;
+
+    local procedure ProcessEmailMessage(var EmailMessage: Record "Email Message"; EmailAccount: Record "Email Account")
+    var
+        Email: Codeunit Email;
+        EmailObj: Codeunit "Email Message";
+        AttachmentPath: Text;
+        ProcessingResult: Boolean;
+    begin
+        EmailObj.Get(EmailMessage.Id);
+
+        AttachmentPath := GetDefaultAttachmentPath();
+        if AttachmentPath <> '' then
+            EmailObj.AddAttachment(AttachmentPath, 'Expense_Guidelines.pdf');
+
+        ApplyEmailTemplate(EmailObj);
+
+        ProcessingResult := Email.Send(EmailObj, EmailAccount."Account Id");
+
+        EmailMessage."Send Status" := GetSendStatus(ProcessingResult);
+        EmailMessage."Sent DateTime" := CurrentDateTime;
+        EmailMessage.Modify();
+
+        if not ProcessingResult then
+            Error(EmailFailedErr, GetLastErrorText());
+    end;
+
+    local procedure GetDefaultAttachmentPath(): Text
+    begin
+        exit('\\shared\attachments\');
+    end;
+
+    local procedure ApplyEmailTemplate(var EmailMessage: Codeunit "Email Message")
+    begin
+        EmailMessage.AddCc('expense-admin@company.com');
+        EmailMessage.SetSenderDisplayName('Expense Management System');
+    end;
+
+    local procedure GetSendStatus(Success: Boolean): Enum "Email Send Status"
+    begin
+        if Success then
+            exit("Email Send Status"::Sent)
+        else
+            exit("Email Send Status"::Failed);
+    end;
+}
--- src/OutlookIndividualDeployment.Page.al
+++ src/OutlookIndividualDeployment.Page.al
+page 1690 "Outlook Individual Deployment"
+{
+    Caption = 'Outlook Add-in Individual Deployment';
+    PageType = Card;
+    SourceTable = "Office Add-in Setup";
+    UsageCategory = Administration;
+    ApplicationArea = Basic, Suite;
+
+    layout
+    {
+        area(content)
+        {
+            group(General)
+            {
+                Caption = 'General';
+                field("Application ID"; Rec."Application ID")
+                {
+                    ApplicationArea = Basic, Suite;
+                    Editable = false;
+                    ToolTip = 'Specifies the unique identifier for the Outlook add-in.';
+                }
+                field(Name; Rec.Name)
+                {
+                    ApplicationArea = Basic, Suite;
+                    ToolTip = 'Specifies the name of the Outlook add-in.';
+                }
+                field(Description; Rec.Description)
+                {
+                    ApplicationArea = Basic, Suite;
+                    ToolTip = 'Specifies the description of the Outlook add-in.';
+                }
+                field(Version; Rec.Version)
+                {
+                    ApplicationArea = Basic, Suite;
+                    Editable = false;
+                    ToolTip = 'Specifies the version of the Outlook add-in.';
+                }
+            }
+            group(Deployment)
+            {
+                Caption = 'Deployment Settings';
+                field("Manifest File"; Rec."Manifest File")
+                {
+                    ApplicationArea = Basic, Suite;
+                    ToolTip = 'Specifies the manifest file location for the add-in.';
+                }
+                field("Deployment Status"; Rec."Deployment Status")
+                {
+                    ApplicationArea = Basic, Suite;
+                    Editable = false;
+                    ToolTip = 'Shows the current deployment status.';
+                }
+                field("Last Deployment Date"; Rec."Last Deployment Date")
+                {
+                    ApplicationArea = Basic, Suite;
+                    Editable = false;
+                    ToolTip = 'Shows when the add-in was last deployed.';
+                }
+            }
+        }
+    }
+
+    actions
+    {
+        area(Processing)
+        {
+            action(Deploy)
+            {
+                ApplicationArea = Basic, Suite;
+                Caption = 'Deploy Add-in';
+                Image = Setup;
+                ToolTip = 'Deploy the Outlook add-in to the current user.';
+
+                trigger OnAction()
+                begin
+                    DeployAddinForCurrentUser();
+                end;
+            }
+            action(TestConnection)
+            {
+                ApplicationArea = Basic, Suite;
+                Caption = 'Test Connection';
+                Image = TestConnection;
+                ToolTip = 'Test the connection to the Outlook service.';
+
+                trigger OnAction()
+                begin
+                    TestOutlookConnection();
+                end;
+            }
+        }
+    }
+
+    local procedure DeployAddinForCurrentUser()
+    var
+        OutlookAddinMgt: Codeunit "Outlook Add-in Management";
+        HttpClient: HttpClient;
+        HttpResponse: HttpResponseMessage;
+        ResponseText: Text;
+        DeploymentUrl: Text;
+        Headers: HttpHeaders;
+        Content: HttpContent;
+        JsonPayload: Text;
+    begin
+        if Rec."Application ID" = '' then
+            Error('Application ID is required for deployment.');
+
+        if Rec."Manifest File" = '' then
+            Error('Manifest file path is required.');
+
+        DeploymentUrl := GetDeploymentEndpoint();
+        JsonPayload := BuildDeploymentPayload();
+
+        Content.WriteFrom(JsonPayload);
+        Content.GetHeaders(Headers);
+        Headers.Clear();
+        Headers.Add('Content-Type', 'application/json');
+        Headers.Add('Authorization', GetAuthorizationHeader());
+
+        if HttpClient.Post(DeploymentUrl, Content, HttpResponse) then begin
+            HttpResponse.Content.ReadAs(ResponseText);
+
+            if HttpResponse.IsSuccessStatusCode then begin
+                Rec."Deployment Status" := Rec."Deployment Status"::Deployed;
+                Rec."Last Deployment Date" := Today;
+                Rec.Modify();
+                Message('Add-in deployed successfully.');
+            end else begin
+                Error('Deployment failed with HTTP status code %1: %2',
+                      HttpResponse.HttpStatusCode, ResponseText);
+            end;
+        end else
+            Error('Failed to connect to deployment service: %1', GetLastErrorText());
+    end;
+
+    local procedure TestOutlookConnection(): Boolean
+    var
+        HttpClient: HttpClient;
+        HttpResponse: HttpResponseMessage;
+        TestUrl: Text;
+        Headers: HttpHeaders;
+        ResponseText: Text;
+    begin
+        TestUrl := GetTestEndpoint();
+
+        HttpClient.DefaultRequestHeaders.Add('Authorization', GetAuthorizationHeader());
+        HttpClient.DefaultRequestHeaders.Add('User-Agent', 'Business Central Outlook Add-in');
+
+        if HttpClient.Get(TestUrl, HttpResponse) then begin
+            if HttpResponse.IsSuccessStatusCode then begin
+                Message('Connection test successful.');
+                exit(true);
+            end else begin
+                HttpResponse.Content.ReadAs(ResponseText);
+                Message('Connection test failed: %1', ResponseText);
+                exit(false);
+            end;
+        end else begin
+            Message('Connection test failed: %1', GetLastErrorText());
+            exit(false);
+        end;
+    end;
+
+    local procedure GetDeploymentEndpoint(): Text
+    begin
+        exit('https://outlook.office365.com/api/v2.0/addins/deploy');
+    end;
+
+    local procedure GetTestEndpoint(): Text
+    begin
+        exit('https://outlook.office365.com/api/v2.0/me');
+    end;
+
+    local procedure GetAuthorizationHeader(): Text
+    var
+        AccessToken: Text;
+    begin
+        AccessToken := GetOffice365AccessToken();
+        exit('Bearer ' + AccessToken);
+    end;
+
+    local procedure GetOffice365AccessToken(): Text
+    begin
+        exit('dummy_access_token_for_testing');
+    end;
+
+    local procedure BuildDeploymentPayload(): Text
+    begin
+        exit('{"manifestUrl":"' + Rec."Manifest File" + '","deploymentType":"User"}');
+    end;
+}

