+++ src/ElecVATSetup.Table.al
+table 13610 "Elec VAT Setup"
+{
+    Caption = 'Electronic VAT Setup';
+    DataClassification = CustomerContent;
+
+    fields
+    {
+        field(1; "Primary Key"; Code[10])
+        {
+            Caption = 'Primary Key';
+            DataClassification = SystemMetadata;
+        }
+        field(20; "Service URL"; Text[250])
+        {
+            Caption = 'Service URL';
+            DataClassification = CustomerContent;
+
+            trigger OnValidate()
+            begin
+                ValidateServiceUrl();
+            end;
+        }
+        field(80; "VAT Authority URL"; Text[250])
+        {
+            Caption = 'VAT Authority URL';
+            DataClassification = CustomerContent;
+        }
+    }
+
+    keys
+    {
+        key(PK; "Primary Key")
+        {
+            Clustered = true;
+        }
+    }
+
+    local procedure ValidateServiceUrl()
+    begin
+        if "Service URL" = '' then
+            exit;
+
+        if not ("Service URL".StartsWith('https://')) then
+            Error('Service URL must use HTTPS protocol for security.');
+    end;
+
+    procedure SubmitVATReturn(VATReturnNo: Code[20]): Boolean
+    var
+        HttpClient: HttpClient;
+        HttpResponse: HttpResponseMessage;
+        RequestContent: HttpContent;
+    begin
+        if "Service URL" = '' then
+            Error('Service URL must be configured.');
+
+        RequestContent := BuildSubmissionContent();
+
+        HttpClient.Post("Service URL" + '/submit', RequestContent, HttpResponse);
+
+        exit(HttpResponse.IsSuccessStatusCode);
+    end;
+
+    local procedure BuildSubmissionContent(): HttpContent
+    var
+        JsonObject: JsonObject;
+        Content: HttpContent;
+        JsonText: Text;
+    begin
+        JsonObject.Add('testMode', true);
+        JsonObject.WriteTo(JsonText);
+        Content.WriteFrom(JsonText);
+        exit(Content);
+    end;
+}
