--- src/EANotifDispatcher.Codeunit.al
+++ src/EANotifDispatcher.Codeunit.al
+codeunit 50900 "EA Notif Dispatcher"
+{
+    TableNo = "Expense Notification";
+
+    var
+        NoEmailConfigErr: Label 'No email configuration found for expense notifications.';
+
+    trigger OnRun()
+    begin
+        SendExpenseReportNotification(Rec."Expense Report No.", Rec."Employee Email");
+    end;
+
+    procedure SendExpenseReportNotification(ExpenseReportNo: Code[20]; EmployeeEmail: Text)
+    var
+        ExpenseReportHeader: Record "Expense Report Header";
+        Recipients: List of [Text];
+        Subject: Text;
+        HtmlBody: Text;
+        EmployeeName: Text;
+    begin
+        if not ExpenseReportHeader.Get(ExpenseReportNo) then
+            Error('Expense report %1 not found.', ExpenseReportNo);
+
+        if EmployeeEmail = '' then
+            Error('No email recipient for expense report %1.', ExpenseReportNo);
+
+        Recipients.Add(EmployeeEmail);
+        EmployeeName := ExpenseReportHeader."Employee Name";
+        Subject := StrSubstNo('Expense Report %1 Status Update', ExpenseReportNo);
+
+        // User-supplied EmployeeName and Description concatenated into HTML without encoding - XSS vulnerability
+        HtmlBody := '<html><body>';
+        HtmlBody += '<h2>Expense Report Update</h2>';
+        HtmlBody += '<p>Dear ' + EmployeeName + ',</p>';
+        HtmlBody += '<p>Your expense report has been updated:</p>';
+        HtmlBody += '<table border="1">';
+        HtmlBody += '<tr><th>Report No.</th><td>' + ExpenseReportNo + '</td></tr>';
+        HtmlBody += '<tr><th>Description</th><td>' + ExpenseReportHeader.Description + '</td></tr>';
+        HtmlBody += '<tr><th>Status</th><td>' + Format(ExpenseReportHeader.Status) + '</td></tr>';
+        HtmlBody += '</table>';
+        HtmlBody += '<p>Thank you,<br/>Expense Management System</p>';
+        HtmlBody += '</body></html>';
+
+        SendEmailNotification(Recipients, Subject, HtmlBody);
+    end;
+
+    local procedure SendEmailNotification(Recipients: List of [Text]; Subject: Text; HtmlMessage: Text)
+    var
+        EmailAccount: Record "Email Account";
+        Email: Codeunit Email;
+        EmailMessage: Codeunit "Email Message";
+        SendResult: Boolean;
+    begin
+        EmailAccount.SetRange("Default Account", true);
+        if not EmailAccount.FindFirst() then
+            Error(NoEmailConfigErr);
+
+        EmailMessage.Create(Recipients, Subject, HtmlMessage, true);
+        SendResult := Email.Send(EmailMessage);
+
+        if not SendResult then
+            Error('Failed to send expense notification email.');
+    end;
+}
+

