--- src/DataProcessor.Codeunit.al
+++ src/DataProcessor.Codeunit.al
+codeunit 50402 "Data Processor"
+{
+    Access = Public;
+
+    procedure CalculateTotalsWithTempTable(var SalesLine: Record "Sales Line")
+    var
+        TempItemCache: Record Item temporary;
+        Item: Record Item;
+        UnitCost: Decimal;
+        TotalCost: Decimal;
+    begin
+        if SalesLine.FindSet() then
+            repeat
+                if not TempItemCache.Get(SalesLine."No.") then begin
+                    Item.SetLoadFields("Unit Cost");
+                    Item.Get(SalesLine."No.");
+                    TempItemCache.Init();
+                    TempItemCache := Item;
+                    TempItemCache.Insert();
+                end;
+                UnitCost := TempItemCache."Unit Cost";
+                TotalCost += SalesLine.Quantity * UnitCost;
+            until SalesLine.Next() = 0;
+    end;
+
+    procedure CalculateTotalsWithDictionary(var SalesLine: Record "Sales Line")
+    var
+        UnitCostCache: Dictionary of [Code[20], Decimal];
+        Item: Record Item;
+        UnitCost: Decimal;
+        TotalCost: Decimal;
+    begin
+        if SalesLine.FindSet() then
+            repeat
+                if not UnitCostCache.ContainsKey(SalesLine."No.") then begin
+                    Item.SetLoadFields("Unit Cost");
+                    Item.Get(SalesLine."No.");
+                    UnitCostCache.Add(SalesLine."No.", Item."Unit Cost");
+                end;
+                UnitCost := UnitCostCache.Get(SalesLine."No.");
+                TotalCost += SalesLine.Quantity * UnitCost;
+            until SalesLine.Next() = 0;
+    end;
+
+    procedure BuildCurrencyMap(var CurrencyMap: Dictionary of [Code[10], Text[30]])
+    var
+        Currency: Record Currency;
+    begin
+        Clear(CurrencyMap);
+        if Currency.FindSet() then
+            repeat
+                CurrencyMap.Add(Currency.Code, Currency.Description);
+            until Currency.Next() = 0;
+    end;
+
+    procedure GetCustomerCurrency(CustomerNo: Code[20]): Code[10]
+    var
+        Customer: Record Customer;
+    begin
+        Customer.SetLoadFields("Currency Code");
+        if Customer.Get(CustomerNo) then
+            exit(Customer."Currency Code")
+        else
+            exit('');
+    end;
+
+    procedure ApplyDiscounts(var SalesLine: Record "Sales Line"; DiscountPct: Decimal)
+    var
+        LineAmount: Decimal;
+    begin
+        if SalesLine.FindSet(true) then
+            repeat
+                LineAmount := SalesLine."Line Amount" * (1 - DiscountPct / 100);
+                SalesLine.Validate("Line Amount", LineAmount);
+                SalesLine.Modify(true);
+            until SalesLine.Next() = 0;
+    end;
+}
+

