+++ src/BOMBufferMgt.Codeunit.al
+codeunit 50142 "BOM Buffer Management"
+{
+    Access = Public;
+
+    procedure CalcTotalCost(var BOMBuffer: Record "BOM Buffer")
+    var
+        Item: Record Item;
+        TotalCost: Decimal;
+        LineCount: Integer;
+    begin
+        // Initialize calculation
+        TotalCost := 0;
+        LineCount := 0;
+
+        // Validate BOM buffer has records
+        if BOMBuffer.IsEmpty() then
+            exit;
+
+        if BOMBuffer.FindSet() then
+            repeat
+                LineCount += 1;
+
+                // Bad: N+1 — Item.Get for every BOM buffer record
+                if Item.Get(BOMBuffer."No.") then begin
+                    // Calculate cost based on costing method
+                    if ShouldUseStandardCost(Item) then
+                        TotalCost += Item."Standard Cost" * BOMBuffer.Quantity
+                    else if ShouldUseAverageCost(Item) then
+                        TotalCost += Item."Unit Cost" * BOMBuffer.Quantity
+                    else
+                        TotalCost += GetLastDirectCost(Item) * BOMBuffer.Quantity;
+                end;
+
+                // Update line with calculated cost
+                UpdateBOMLineWithCost(BOMBuffer, Item);
+
+            until BOMBuffer.Next() = 0;
+
+        // Log calculation summary
+        LogCostCalculation(LineCount, TotalCost);
+    end;
+
+    local procedure ShouldUseStandardCost(Item: Record Item): Boolean
+    begin
+        exit(Item."Costing Method" = Item."Costing Method"::Standard);
+    end;
+
+    local procedure ShouldUseAverageCost(Item: Record Item): Boolean
+    begin
+        exit(Item."Costing Method" = Item."Costing Method"::Average);
+    end;
+
+    local procedure GetLastDirectCost(Item: Record Item): Decimal
+    begin
+        exit(Item."Last Direct Cost");
+    end;
+
+    local procedure UpdateBOMLineWithCost(var BOMBuffer: Record "BOM Buffer"; Item: Record Item)
+    begin
+        BOMBuffer."Unit Cost" := Item."Unit Cost";
+        BOMBuffer."Total Cost" := BOMBuffer."Unit Cost" * BOMBuffer.Quantity;
+        BOMBuffer.Modify();
+    end;
+
+    local procedure LogCostCalculation(LineCount: Integer; TotalCost: Decimal)
+    begin
+        // Log calculation summary for audit
+    end;
+}
