+    procedure IsFeatureEnabled(FeatureKey: Text[50]): Boolean
+    var
+        FeatureDataUpdateStatus: Record "Feature Data Update Status";
+    begin
+        FeatureDataUpdateStatus.ReadIsolation := IsolationLevel::ReadCommitted;
