--- src/AssemblyLineMgt.Codeunit.al
+++ src/AssemblyLineMgt.Codeunit.al
+codeunit 50172 "Assembly Line Check"
+{
+    Access = Public;
+
+    procedure CheckAvailability(AssemblyLine: Record "Assembly Line"): Boolean
+    var
+        AssemblyLineCheck: Record "Assembly Line";
+    begin
+        AssemblyLineCheck.Get(AssemblyLine."Document Type", AssemblyLine."Document No.", AssemblyLine."Line No.");
+
+        if AssemblyLineCheck.Quantity <= 0 then
+            exit(false);
+
+        if AssemblyLineCheck.Type <> AssemblyLineCheck.Type::Item then
+            exit(true);
+
+        exit(AssemblyLineCheck."No." <> '');
+    end;
+
+    procedure ValidateAssemblyLineQuantity(var AssemblyLine: Record "Assembly Line")
+    begin
+        if AssemblyLine.Quantity <= 0 then
+            Error('Quantity must be greater than zero');
+
+        if AssemblyLine.Type = AssemblyLine.Type::Item then
+            if not CheckAvailability(AssemblyLine) then
+                Message('Insufficient inventory available for item %1', AssemblyLine."No.");
+    end;
+}
--- src/PurchAllocAccMgt.Codeunit.al
+++ src/PurchAllocAccMgt.Codeunit.al
+codeunit 50170 "Purchase Alloc. Acc. Mgt."
+{
+    Access = Public;
+
+    procedure DistributeAmount(PurchaseLine: Record "Purchase Line")
+    var
+        PurchaseHeader: Record "Purchase Header";
+        AllocationAccount: Record "Allocation Account";
+    begin
+        // Bad: Get before guard — wasted DB call when allocation not set
+        PurchaseHeader.Get(PurchaseLine."Document Type", PurchaseLine."Document No.");
+
+        // Guard condition - should be checked first
+        if PurchaseLine."Selected Alloc. Account No." = '' then
+            exit;
+
+        // Validate allocation account exists
+        if not AllocationAccount.Get(PurchaseLine."Selected Alloc. Account No.") then
+            Error('Allocation account %1 does not exist.', PurchaseLine."Selected Alloc. Account No.");
+
+        // Validate account is active
+        AllocationAccount.TestField(Blocked, false);
+
+        // Perform the distribution
+        DistributeToAllocAccount(PurchaseHeader, PurchaseLine, AllocationAccount);
+
+        // Update line with distribution status
+        UpdateLineDistributionStatus(PurchaseLine);
+    end;
+
+    procedure ValidateAllocationSetup(PurchaseLine: Record "Purchase Line"): Boolean
+    var
+        AllocationAccount: Record "Allocation Account";
+    begin
+        if PurchaseLine."Selected Alloc. Account No." = '' then
+            exit(false);
+
+        if not AllocationAccount.Get(PurchaseLine."Selected Alloc. Account No.") then
+            exit(false);
+
+        exit(not AllocationAccount.Blocked);
+    end;
+
+    local procedure DistributeToAllocAccount(PurchaseHeader: Record "Purchase Header"; PurchaseLine: Record "Purchase Line"; AllocationAccount: Record "Allocation Account")
+    var
+        PurchaseLineAllocation: Record "Purchase Line - Alloc. Acc.";
+    begin
+        // Create distribution entries
+        PurchaseLineAllocation.Init();
+        PurchaseLineAllocation."Document Type" := PurchaseLine."Document Type";
+        PurchaseLineAllocation."Document No." := PurchaseLine."Document No.";
+        PurchaseLineAllocation."Line No." := PurchaseLine."Line No.";
+        PurchaseLineAllocation."Allocation Account No." := AllocationAccount."No.";
+        PurchaseLineAllocation.Amount := PurchaseLine."Line Amount";
+        PurchaseLineAllocation.Insert();
+    end;
+
+    local procedure UpdateLineDistributionStatus(var PurchaseLine: Record "Purchase Line")
+    begin
+        PurchaseLine."Alloc. Acc. Distribution Date" := Today();
+        PurchaseLine."Distribution Complete" := true;
+        PurchaseLine.Modify();
+    end;
+}
--- src/SKUMgt.Codeunit.al
+++ src/SKUMgt.Codeunit.al
+codeunit 50171 "SKU Management"
+{
+    Access = Public;
+
+    procedure CheckSKUCreationPolicy(LocationCode: Code[10]): Boolean
+    var
+        Location: Record Location;
+    begin
+        if LocationCode = '' then
+            exit(false);
+
+        Location.Get(LocationCode);
+        Location.TestField("SKU Creation Policy");
+
+        exit(Location."SKU Creation Policy" <> Location."SKU Creation Policy"::Never);
+    end;
+
+    procedure CreateSKUForItem(ItemNo: Code[20]; LocationCode: Code[10])
+    var
+        Item: Record Item;
+        StockkeepingUnit: Record "Stockkeeping Unit";
+    begin
+        if (ItemNo = '') or (LocationCode = '') then
+            exit;
+
+        if not CheckSKUCreationPolicy(LocationCode) then
+            Error('SKU creation is not allowed for location %1', LocationCode);
+
+        Item.SetLoadFields(Description, "Unit Cost", "Standard Cost");
+        Item.Get(ItemNo);
+
+        if StockkeepingUnit.Get(LocationCode, ItemNo, '') then
+            exit;
+
+        StockkeepingUnit.Init();
+        StockkeepingUnit."Location Code" := LocationCode;
+        StockkeepingUnit."Item No." := ItemNo;
+        StockkeepingUnit."Variant Code" := '';
+        StockkeepingUnit.Description := Item.Description;
+        StockkeepingUnit."Unit Cost" := Item."Unit Cost";
+        StockkeepingUnit."Standard Cost" := Item."Standard Cost";
+        StockkeepingUnit.Insert();
+
+        LogSKUCreation(ItemNo, LocationCode);
+    end;
+
+    procedure GetSKUPolicy(LocationCode: Code[10]): Integer
+    var
+        Location: Record Location;
+    begin
+        if LocationCode = '' then
+            exit(0);
+
+        Location.SetLoadFields("SKU Creation Policy");
+        if Location.Get(LocationCode) then
+            exit(Location."SKU Creation Policy".AsInteger());
+        exit(0);
+    end;
+
+    local procedure LogSKUCreation(ItemNo: Code[20]; LocationCode: Code[10])
+    begin
+        // Log SKU creation for audit purposes
+    end;
+}

--- src/ReportBuilder.Codeunit.al
+++ src/ReportBuilder.Codeunit.al
+codeunit 50401 "Report Builder"
+{
+    Access = Public;
+
+    procedure BuildCsvExport(CustomerNo: Code[20]): Text
+    var
+        SalesLine: Record "Sales Line";
+        Result: Text;
+    begin
+        SalesLine.SetRange("Sell-to Customer No.", CustomerNo);
+        SalesLine.SetRange("Document Type", SalesLine."Document Type"::Order);
+        SalesLine.SetLoadFields("No.", Description, Quantity, "Line Amount");
+        Result := 'Item No.,Description,Quantity,Amount';
+        if SalesLine.FindSet() then
+            repeat
+                Result += Format(SalesLine."No.") + ',' +
+                    SalesLine.Description + ',' +
+                    Format(SalesLine.Quantity) + ',' +
+                    Format(SalesLine."Line Amount");
+            until SalesLine.Next() = 0;
+        exit(Result);
+    end;
+
+    procedure BuildHtmlNotification(VendorNo: Code[20]): Text
+    var
+        VendorLedgerEntry: Record "Vendor Ledger Entry";
+        HtmlBody: Text;
+    begin
+        HtmlBody := '<html><body><table>';
+        HtmlBody += '<tr><th>Entry No.</th><th>Description</th><th>Amount</th></tr>';
+        VendorLedgerEntry.SetRange("Vendor No.", VendorNo);
+        VendorLedgerEntry.SetRange(Open, true);
+        VendorLedgerEntry.SetLoadFields(Description);
+        if VendorLedgerEntry.FindSet() then
+            repeat
+                VendorLedgerEntry.CalcFields("Remaining Amount");
+                HtmlBody += '<tr><td>' + Format(VendorLedgerEntry."Entry No.") + '</td>' +
+                    '<td>' + VendorLedgerEntry.Description + '</td>' +
+                    '<td>' + Format(VendorLedgerEntry."Remaining Amount") + '</td></tr>';
+            until VendorLedgerEntry.Next() = 0;
+        HtmlBody += '</table></body></html>';
+        exit(HtmlBody);
+    end;
+
+    procedure BuildItemSummary(LocationCode: Code[10]): Text
+    var
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        Summary: TextBuilder;
+    begin
+        Summary.Append('Location: ' + LocationCode);
+        Summary.AppendLine();
+        Summary.Append('Item No. | Description | Quantity');
+        Summary.AppendLine();
+        ItemLedgerEntry.SetRange("Location Code", LocationCode);
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Purchase);
+        ItemLedgerEntry.SetLoadFields("Item No.", Description, Quantity);
+        if ItemLedgerEntry.FindSet() then
+            repeat
+                Summary.Append(ItemLedgerEntry."Item No.");
+                Summary.Append(' | ');
+                Summary.Append(ItemLedgerEntry.Description);
+                Summary.Append(' | ');
+                Summary.Append(Format(ItemLedgerEntry.Quantity));
+                Summary.AppendLine();
+            until ItemLedgerEntry.Next() = 0;
+        exit(Summary.ToText());
+    end;
+}
