+    procedure LookupPostalAddress(PostalCode: Code[20]; City: Text[50]): Text[250]
+    var
+        HttpClient: HttpClient;
+        HttpResponse: HttpResponseMessage;
+        RequestUri: Text;
+        ResponseText: Text;
