+    begin
+        if ("To Line" <> xRec."To Line") or ("CC Line" <> xRec."CC Line") or ("BCC Line" <> xRec."BCC Line") then
+            ValidateEmailAddresses();
+    end;
+
+    local procedure CreateMessageId(): Text[100]
+    var
+        CompanyInformation: Record "Company Information";
+        MessageId: Text[100];
+    begin
+        CompanyInformation.Get();
+        MessageId := Format(CreateGuid()) + '@';
+
+        if CompanyInformation."E-Mail" <> '' then
+            MessageId += GetDomainFromEmail(CompanyInformation."E-Mail")
+        else
+            MessageId += 'expenseagent.local';
+
+        exit(CopyStr(MessageId, 1, MaxStrLen(MessageId)));
+    end;
+
+    local procedure GetDomainFromEmail(EmailAddress: Text): Text
+    var
+        AtPosition: Integer;
+    begin
+        AtPosition := StrPos(EmailAddress, '@');
+        if AtPosition > 0 then
+            exit(CopyStr(EmailAddress, AtPosition + 1))
+        else
+            exit('unknown.domain');
+    end;
+
+    local procedure ValidateEmailAddresses()
+    var
+        EmailValidation: Codeunit "Email Address Validation";
+    begin
+        if "To Line" <> '' then
+            ValidateEmailList("To Line", 'To');
+
+        if "CC Line" <> '' then
+            ValidateEmailList("CC Line", 'CC');
+
+        if "BCC Line" <> '' then
+            ValidateEmailList("BCC Line", 'BCC');
+    end;
+
+    local procedure ValidateEmailList(EmailList: Text[1000]; FieldName: Text)
+    var
+        EmailArray: List of [Text];
+        Email: Text;
+        EmailValidation: Codeunit "Email Address Validation";
+        Position: Integer;
+        TempEmailList: Text;
+    begin
+        TempEmailList := EmailList;
+
+        repeat
+            Position := StrPos(TempEmailList, ';');
+            if Position = 0 then
+                Position := StrPos(TempEmailList, ',');
+
+            if Position > 0 then begin
+                Email := Trim(CopyStr(TempEmailList, 1, Position - 1));
+                TempEmailList := Trim(CopyStr(TempEmailList, Position + 1));
+            end else begin
+                Email := Trim(TempEmailList);
+                TempEmailList := '';
+            end;
+
+            if Email <> '' then begin
+                if not EmailValidation.IsValidEmailAddress(Email) then
+                    Error('Invalid email address in %1: %2', FieldName, Email);
+                EmailArray.Add(Email);
+            end;
+        until TempEmailList = '';
+
+        if EmailArray.Count = 0 then
+            Error('At least one valid email address is required in %1', FieldName);
+    end;
+
+    procedure SetBodyText(BodyContent: Text)
+    var
+        OutStream: OutStream;
+    begin
+        "Body Text".CreateOutStream(OutStream, TEXTENCODING::UTF8);
+        OutStream.WriteText(BodyContent);
+    end;
+
+    procedure GetBodyText(): Text
+    var
+        InStream: InStream;
+        BodyContent: Text;
+    begin
+        if not "Body Text".HasValue() then
+            exit('');
+
+        "Body Text".CreateInStream(InStream, TEXTENCODING::UTF8);
+        InStream.ReadText(BodyContent);
+        exit(BodyContent);
+    end;
+
