+codeunit 50114 OutlookIntegrationHelper
+{
+    var
+        // Privacy notice ID registered via Privacy Notice Registrations — text constants are the standard BC pattern for privacy notice IDs
+        GraphNotificationTxt: Label 'MicrosoftGraphNotification', Locked = true;
+
+    procedure SendBusinessNotification(BusinessEmail: Text[250]; NotificationType: Text[50])
+    var
+        PrivacyNotice: Codeunit "Privacy Notice";
+        PrivacyNoticeReg: Codeunit "Privacy Notice Registrations";
+        HttpClient: HttpClient;
+        HttpRequest: HttpRequestMessage;
+        HttpResponse: HttpResponseMessage;
+        JsonPayload: JsonObject;
+        PayloadText: Text;
+    begin
+        if not (PrivacyNotice.GetPrivacyNoticeApprovalState(GraphNotificationTxt) = "Privacy Notice Approval State"::Agreed) then
+            Error('Privacy notice for Microsoft Graph notifications has not been accepted.');
+
+        JsonPayload.Add('recipient', BusinessEmail);
+        JsonPayload.Add('type', NotificationType);
+        JsonPayload.Add('timestamp', CurrentDateTime);
+        JsonPayload.WriteTo(PayloadText);
+
+        HttpRequest.SetRequestUri('https://graph.microsoft.com/v1.0/business/notifications');
+        HttpRequest.Content.WriteFrom(PayloadText);
+        HttpRequest.Content.GetHeaders().Add('Content-Type', 'application/json');
+
+        if HttpClient.Send(HttpRequest, HttpResponse) then
+            Message('Business notification sent successfully')
+        else
+            Error('Failed to send business notification');
+    end;
+
+    procedure ProcessBusinessContacts(var BusinessContact: Record "Business Contact")
+    var
+        ContactEmail: Text[250];
+        ProcessedCount: Integer;
+    begin
+        if BusinessContact.FindSet() then
+            repeat
+                ContactEmail := BusinessContact."Email Address";
+
+                if IsValidBusinessEmail(ContactEmail) then begin
+                    SendBusinessNotification(ContactEmail, 'BUSINESS_UPDATE');
+                    ProcessedCount += 1;
+                end;
+            until BusinessContact.Next() = 0;
+
+        Message('Processed %1 business email notifications', ProcessedCount);
+    end;
+
+    local procedure IsValidBusinessEmail(Email: Text[250]): Boolean
+    begin
+        exit((Email <> '') and (StrPos(Email, '@') > 0));
+    end;
+}
--- src/SOAFiltersImpl.Codeunit.al
+++ src/SOAFiltersImpl.Codeunit.al
+namespace Microsoft.SalesOrderAgent.Validation;
+
+using Microsoft.SalesOrderAgent.Integration;
+using Microsoft.Foundation.NoSeries;
+using System.Utilities;
+
+codeunit 57003 "SOA Filters Impl"
+{
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        EmailValidationLib: Codeunit "Email Address";
+        InvalidEmailFormatMsg: Label 'Invalid email format in filter: %1', Comment = '%1 = email address';
+        DuplicateEmailWarningMsg: Label 'Email %1 appears multiple times in the filter.', Comment = '%1 = email address';
+        FilterAppliedMsg: Label 'Filter has been applied successfully.';
+
+    procedure ValidateCustomerEmailFilters(var SalesOrderFilters: Record "SOA Sales Order Filters")
+    var
+        TempEmailList: Record "Name/Value Buffer" temporary;
+        EmailText: Text;
+        EmailAddress: Text[250];
+        Position: Integer;
+        Counter: Integer;
+    begin
+        if SalesOrderFilters."Customer Email Filter" = '' then
+            exit;
+
+        EmailText := SalesOrderFilters."Customer Email Filter";
+
+        repeat
+            Position := StrPos(EmailText, ',');
+            if Position > 0 then begin
+                EmailAddress := CopyStr(Trim(CopyStr(EmailText, 1, Position - 1)), 1, 250);
+                EmailText := Trim(CopyStr(EmailText, Position + 1));
+            end else begin
+                EmailAddress := CopyStr(Trim(EmailText), 1, 250);
+                EmailText := '';
+            end;
+
+            if EmailAddress <> '' then begin
+                Counter += 1;
+
+                if not EmailValidationLib.IsValidEmailAddress(EmailAddress) then
+                    Error(InvalidEmailFormatMsg, EmailAddress);
+
+                TempEmailList.SetRange(Name, EmailAddress);
+                if TempEmailList.FindFirst() then
+                    Message(DuplicateEmailWarningMsg, EmailAddress);
+
+                TempEmailList.Init();
+                TempEmailList.Name := EmailAddress;
+                TempEmailList.Value := Format(Counter);
+                TempEmailList.Insert();
+            end;
+        until EmailText = '';
+
+        Message(FilterAppliedMsg);
+    end;
+
+    procedure ApplyEmailNotificationFilter(CustomerEmail: Text[250]; var NotificationSettings: Record "SOA Notification Setup")
+    var
+        EmailFound: Boolean;
+        NotificationMsg: Text;
+    begin
+        if CustomerEmail = '' then
+            exit;
+
+        NotificationSettings.SetRange("Notification Type", NotificationSettings."Notification Type"::"Email Alert");
+        NotificationSettings.SetRange(Enabled, true);
+
+        if NotificationSettings.FindSet() then begin
+            repeat
+                if StrPos(NotificationSettings."Email Filter", CustomerEmail) > 0 then begin
+                    EmailFound := true;
+                    NotificationMsg := StrSubstNo('Customer with email %1 matches notification filter.', CustomerEmail);
+
+                    SendEmailFilterNotification(NotificationMsg, CustomerEmail);
+                end;
+            until NotificationSettings.Next() = 0;
+        end;
+
+        if not EmailFound then begin
+            NotificationMsg := StrSubstNo('No matching notification rule found for email: %1', CustomerEmail);
+            SendEmailFilterNotification(NotificationMsg, CustomerEmail);
+        end;
+    end;
+
+    local procedure SendEmailFilterNotification(NotificationText: Text; CustomerEmail: Text[250])
+    var
+        MyNotifications: Record "My Notifications";
+        NotificationMgt: Codeunit "Notification Management";
+        Notification: Notification;
+    begin
+        if not MyNotifications.IsEnabledForRecord('SOA_EMAIL_FILTER', Database::"SOA Sales Order Filters") then
+            exit;
+
+        Notification.Id := CreateGuid();
+        Notification.Message := NotificationText;
+        Notification.Scope := NotificationScope::LocalScope;
+
+        Notification.SetData('EMAIL', CustomerEmail);
+        Notification.SetData('FILTER_TYPE', 'EMAIL_NOTIFICATION');
+
+        Notification.Send();
+
+        LogEmailNotification(CustomerEmail, NotificationText);
+    end;
+
+    local procedure LogEmailNotification(EmailAddress: Text[250]; NotificationText: Text)
+    var
+        SOAActivityLog: Record "SOA Activity Log";
+    begin
+        SOAActivityLog.Init();
+        SOAActivityLog."Entry No." := GetNextEntryNo();
+        SOAActivityLog."Activity Type" := SOAActivityLog."Activity Type"::Notification;
+        SOAActivityLog."Activity DateTime" := CurrentDateTime;
+        SOAActivityLog."User ID" := UserId;
+        SOAActivityLog.Description := CopyStr(NotificationText, 1, MaxStrLen(SOAActivityLog.Description));
+        SOAActivityLog."Related Email" := EmailAddress;
+        SOAActivityLog."Status" := SOAActivityLog.Status::Completed;
+        SOAActivityLog.Insert(true);
+    end;
+
+    local procedure GetNextEntryNo(): Integer
+    var
+        SOAActivityLog: Record "SOA Activity Log";
+    begin
+        SOAActivityLog.LockTable();
+        if SOAActivityLog.FindLast() then
+            exit(SOAActivityLog."Entry No." + 1)
+        else
+            exit(1);
+    end;
+
+    procedure ProcessCustomerContactEmails(var CustomerRec: Record Customer)
+    var
+        Contact: Record Contact;
+        ContactBusinessRelation: Record "Contact Business Relation";
+        EmailProcessor: Codeunit "SOA Email Processor";
+    begin
+        ContactBusinessRelation.SetCurrentKey("Link to Table", "No.");
+        ContactBusinessRelation.SetRange("Link to Table", ContactBusinessRelation."Link to Table"::Customer);
+        ContactBusinessRelation.SetRange("No.", CustomerRec."No.");
+
+        if ContactBusinessRelation.FindFirst() then begin
+            Contact.SetRange("Company No.", ContactBusinessRelation."Contact No.");
+            Contact.SetRange(Type, Contact.Type::Person);
+            Contact.SetFilter("E-Mail", '<>%1', '');
+
+            if Contact.FindSet() then
+                repeat
+                    EmailProcessor.QueueContactEmailValidation(Contact."E-Mail", Contact."No.", CustomerRec."No.");
+                until Contact.Next() = 0;
+        end;
+    end;
+}

