+    begin
+        if DisplayName <> '' then
+            exit(DisplayName);
+        if (GivenName <> '') and (Surname <> '') then
+            exit(GivenName + ' ' + Surname);
+        if GivenName <> '' then
+            exit(GivenName);
+        if Surname <> '' then
+            exit(Surname);
+        exit('');
+    end;
+}
