+
+    trigger OnModify()
+    begin
+        "Modified DateTime" := CurrentDateTime;
+
+        if "Manager User Security ID" <> xRec."Manager User Security ID" then
+            ValidateManagerHierarchy();
+
+        if "Employee No." <> xRec."Employee No." then
+            SyncWithEmployee();
+    end;
+
+    trigger OnDelete()
+    var
+        ExpenseHeader: Record "Expense Header";
+        SubordinateUser: Record "Expense User";
+    begin
+        ExpenseHeader.SetRange("Employee No.", "Employee No.");
+        ExpenseHeader.SetFilter(Status, '<>%1', ExpenseHeader.Status::Approved);
+        if not ExpenseHeader.IsEmpty then
+            Error('Cannot delete user %1. There are pending expense documents.', "Full Name");
+
+        SubordinateUser.SetRange("Manager User Security ID", "User Security ID");
+        SubordinateUser.ModifyAll("Manager User Security ID", "User Security ID");
+    end;
+
