+        if not EmailValidation.IsValidEmailAddress(eMail) then
+            Error('Invalid email address format: %1', eMail);
+
+        DuplicateUser.SetCurrentKey(eMail);
+        DuplicateUser.SetRange(eMail, eMail);
+        DuplicateUser.SetFilter("User Security ID", '<>%1', "User Security ID");
+        DuplicateUser.SetRange("Is Active", true);
+
+        if DuplicateUser.FindFirst() then
+            Error('Email address %1 is already in use by %2', eMail, DuplicateUser."Full Name");
+    end;
