+    local procedure ValidateManagerHierarchy()
+    var
+        ManagerUser: Record "Expense User";
+        Employee: Record Employee;
+    begin
+        if IsNullGuid("Manager User Security ID") then
+            exit;
+
+        if "Manager User Security ID" = "User Security ID" then
+            Error('A user cannot be their own manager.');
+
+        ManagerUser.SetRange("User Security ID", "Manager User Security ID");
+        ManagerUser.SetRange("Is Active", true);
+
+        if not ManagerUser.FindFirst() then
+            Error('Manager with User Security ID %1 does not exist or is inactive.', "Manager User Security ID");
+
+        if not ManagerUser."Allow Expense Approval" then
+            Error('Manager %1 is not authorized to approve expenses.', ManagerUser."Full Name");
+
+        "Manager Employee No." := ManagerUser."Employee No.";
+    end;
+
+    local procedure SyncWithEmployee()
+    var
+        Employee: Record Employee;
+        User: Record User;
+    begin
+        if Employee.Get("Employee No.") then begin
+            if "Full Name" = '' then
+                "Full Name" := Employee.FullName();
+
+            if eMail = '' then begin
+                if Employee."Company E-Mail" <> '' then
+                    eMail := Employee."Company E-Mail"
+                else if Employee."E-Mail" <> '' then
+                    eMail := Employee."E-Mail";
+            end;
+        end;
+
+        if User.Get("User Security ID") then begin
+            if "User Name" = '' then
+                "User Name" := User."User Name";
+        end;
+    end;
+
+    procedure GetManagerName(): Text[100]
+    var
+        ManagerUser: Record "Expense User";
+    begin
+        if IsNullGuid("Manager User Security ID") then
+            exit('');
+
+        ManagerUser.SetRange("User Security ID", "Manager User Security ID");
+        if ManagerUser.FindFirst() then
+            exit(ManagerUser."Full Name");
+    end;
+
+    procedure HasApprovalRights(): Boolean
+    begin
+        exit("Allow Expense Approval" and "Is Active");
+    end;
+
+    procedure CanApproveAmount(Amount: Decimal): Boolean
+    begin
+        if not HasApprovalRights() then
+            exit(false);
+
+        if "Approval Limit" = 0 then // Unlimited approval
+            exit(true);
+
+        exit(Amount <= "Approval Limit");
+    end;
+
+    procedure UpdateLastLogin()
+    begin
+        "Last Login DateTime" := CurrentDateTime;
+        Modify(false);
+    end;
+
+    var
+        OnlyBCUserCanApproveErr: Label 'Only Business Central users can approve expenses. User %1 with email %2 is not a valid BC user.', Comment = '%1 = Full Name, %2 = Email';
+
+    procedure ValidateBCUserForApproval()
+    var
+        User: Record User;
+        ErrorMsg: Text;
+    begin
+        if not "Allow Expense Approval" then
+            exit;
+
+        User.SetRange("User Security ID", "User Security ID");
+        User.SetRange(State, User.State::Enabled);
+
+        if not User.FindFirst() then begin
+            ErrorMsg := StrSubstNo(OnlyBCUserCanApproveErr, "Full Name", eMail);
+            Error(ErrorMsg);
+        end;
+
+        if User."License Type" = User."License Type"::"External User" then begin
+            ErrorMsg := StrSubstNo(OnlyBCUserCanApproveErr, "Full Name", eMail);
+            Error(ErrorMsg);
+        end;
+    end;
+}
--- src/JobQueueErrorHandler.Codeunit.al
+++ src/JobQueueErrorHandler.Codeunit.al
+namespace System.Threading;
+
+using Microsoft.Foundation.NoSeries;
+using System.Environment.Configuration;
+using System.Telemetry;
+
+codeunit 452 "Job Queue Error Handler"
+{
+    TableNo = "Job Queue Entry";
+
+    trigger OnRun()
+    begin
+        HandleJobQueueError(Rec);
+    end;
+
+    var
+        JobQueueEntryTxt: Label 'Job Queue Entry: %1', Comment = '%1 = Job Queue Entry ID';
+        ErrorProcessingJobTxt: Label 'Error processing job queue entry %1. Error: %2', Comment = '%1 = Job Queue Entry ID, %2 = Error message';
+        RetryAttemptTxt: Label 'Retry attempt %1 of %2 for Job Queue Entry %3', Comment = '%1 = Current attempt, %2 = Max attempts, %3 = Job Queue Entry ID';
+
+    local procedure HandleJobQueueError(var JobQueueEntry: Record "Job Queue Entry")
+    var
+        JobQueueManagement: Codeunit "Job Queue Management";
+        Telemetry: Codeunit Telemetry;
+        ErrorMsg: Text;
+        CustomDimensions: Dictionary of [Text, Text];
+    begin
+        ErrorMsg := GetLastErrorText();
+
+        CustomDimensions.Add('JobQueueEntryId', Format(JobQueueEntry.ID));
+        CustomDimensions.Add('ObjectType', Format(JobQueueEntry."Object Type to Run"));
+        CustomDimensions.Add('ObjectId', Format(JobQueueEntry."Object ID to Run"));
+        CustomDimensions.Add('CompanyName', CompanyName);
+
+        Telemetry.LogMessage('0000ABC', StrSubstNo(ErrorProcessingJobTxt, JobQueueEntry.ID, ErrorMsg),
+                           Verbosity::Error, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+        JobQueueEntry."Error Message" := CopyStr(ErrorMsg, 1, MaxStrLen(JobQueueEntry."Error Message"));
+        JobQueueEntry.Status := JobQueueEntry.Status::Error;
+        JobQueueEntry."No. of Attempts to Run" := JobQueueEntry."No. of Attempts to Run" + 1;
+        JobQueueEntry."Earliest Start Date/Time" := CurrentDateTime + CalculateRetryDelay(JobQueueEntry);
+
+        if ShouldRetryJob(JobQueueEntry) then begin
+            JobQueueEntry.Status := JobQueueEntry.Status::Ready;
+
+            Telemetry.LogMessage('0000ABD', StrSubstNo(RetryAttemptTxt,
+                               JobQueueEntry."No. of Attempts to Run",
+                               JobQueueEntry."Maximum No. of Attempts to Run",
+                               JobQueueEntry.ID),
+                               Verbosity::Warning, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+        end else begin
+            SendFailureNotification(JobQueueEntry, ErrorMsg);
+        end;
+
+        JobQueueEntry."Last Ready State" := CurrentDateTime;
+        JobQueueEntry.Modify(true);
+
+        ClearLastError();
+    end;
+
+    local procedure ShouldRetryJob(JobQueueEntry: Record "Job Queue Entry"): Boolean
+    begin
+        if JobQueueEntry."Maximum No. of Attempts to Run" = 0 then
+            exit(false);
+
+        exit(JobQueueEntry."No. of Attempts to Run" < JobQueueEntry."Maximum No. of Attempts to Run");
+    end;
+
+    local procedure CalculateRetryDelay(JobQueueEntry: Record "Job Queue Entry"): Duration
+    var
+        BaseDelayMinutes: Integer;
+        ExponentialFactor: Integer;
+    begin
+        BaseDelayMinutes := 5;
+        ExponentialFactor := Power(2, JobQueueEntry."No. of Attempts to Run" - 1);
+
+        if BaseDelayMinutes * ExponentialFactor > 240 then
+            ExponentialFactor := 240 div BaseDelayMinutes;
+
+        exit(BaseDelayMinutes * ExponentialFactor * 60 * 1000); // Convert to milliseconds
+    end;
+
+    local procedure SendFailureNotification(JobQueueEntry: Record "Job Queue Entry"; ErrorMessage: Text)
+    var
+        NotificationMgt: Codeunit "Notification Management";
+        Company: Record Company;
+        AdminUser: Record User;
+        EmailMessage: Codeunit "Email Message";
+        Email: Codeunit Email;
+        Subject: Text;
+        Body: Text;
+        ToRecipients: List of [Text];
+    begin
+        AdminUser.SetRange("License Type", AdminUser."License Type"::"Full User");
+        AdminUser.SetFilter("Windows Security ID", '<>%1', '');
+        AdminUser.SetRange(State, AdminUser.State::Enabled);
+
+        if not AdminUser.FindSet() then
+            exit;
+
+        Subject := StrSubstNo('Job Queue Entry Failure - %1', JobQueueEntry.Description);
+
+        Body := 'A job queue entry has failed after exhausting all retry attempts.' + CRLF + CRLF;
+        Body += 'Job Queue Entry ID: ' + Format(JobQueueEntry.ID) + CRLF;
+        Body += 'Description: ' + JobQueueEntry.Description + CRLF;
+        Body += 'Object Type: ' + Format(JobQueueEntry."Object Type to Run") + CRLF;
+        Body += 'Object ID: ' + Format(JobQueueEntry."Object ID to Run") + CRLF;
+        Body += 'Company: ' + CompanyName + CRLF;
+        Body += 'Failed At: ' + Format(CurrentDateTime) + CRLF;
+        Body += 'Attempts Made: ' + Format(JobQueueEntry."No. of Attempts to Run") + CRLF + CRLF;
+        Body += 'Error Message:' + CRLF;
+        Body += ErrorMessage + CRLF + CRLF;
+        Body += 'Please check the Job Queue Entries page for more details and take appropriate action.';
+
+        repeat
+            if AdminUser."Contact Email" <> '' then
+                ToRecipients.Add(AdminUser."Contact Email");
+        until AdminUser.Next() = 0;
+
+        if ToRecipients.Count > 0 then begin
+            EmailMessage.Create(ToRecipients, Subject, Body, true);
+            Email.Send(EmailMessage, Enum::"Email Scenario"::"Job Queue");
+        end;
+    end;
+
+    procedure ResetJobQueueEntry(var JobQueueEntry: Record "Job Queue Entry")
+    var
+        Telemetry: Codeunit Telemetry;
+        CustomDimensions: Dictionary of [Text, Text];
+    begin
+        JobQueueEntry.Status := JobQueueEntry.Status::Ready;
+        JobQueueEntry."No. of Attempts to Run" := 0;
+        Clear(JobQueueEntry."Error Message");
+        JobQueueEntry."Earliest Start Date/Time" := CurrentDateTime;
+        JobQueueEntry."Last Ready State" := CurrentDateTime;
+        JobQueueEntry.Modify(true);
+
+        CustomDimensions.Add('JobQueueEntryId', Format(JobQueueEntry.ID));
+        CustomDimensions.Add('ObjectType', Format(JobQueueEntry."Object Type to Run"));
