--- src/ReleaseExpenseDocument.Codeunit.al
+++ src/ReleaseExpenseDocument.Codeunit.al
+namespace Microsoft.ExpenseAgent.Expense;
+
+using Microsoft.ExpenseAgent.MasterData;
+using Microsoft.Foundation.Reporting;
+using System.Globalization;
+
+codeunit 57089 "Release Expense Document"
+{
+    TableNo = "Expense Header";
+
+    trigger OnRun()
+    begin
+        ReleaseExpenseDocument(Rec);
+    end;
+
+    var
+        ExpenseDocumentReleasedMsg: Label 'Expense document %1 has been released successfully.', Comment = '%1 = Document No.';
+        ExpenseDocumentReleaseFailedErr: Label 'Failed to release expense document %1. Please check the document and try again.', Comment = '%1 = Document No.';
+        MissingApproverErr: Label 'Cannot release expense document %1. No approver is assigned.', Comment = '%1 = Document No.';
+        InsufficientApprovalLimitErr: Label 'Cannot release expense document %1. The assigned approver does not have sufficient approval limits.', Comment = '%1 = Document No.';
+        DocumentAlreadyReleasedErr: Label 'Expense document %1 is already released.', Comment = '%1 = Document No.';
+        InvalidReceiptDataErr: Label 'Invalid receipt data in expense line %1. Receipt No.: %2, Expense Date: %3, Merchant: %4', Comment = '%1 = Line No., %2 = Receipt No., %3 = Expense Date, %4 = Merchant Name';
+
+    procedure ReleaseExpenseDocument(var ExpenseHeader: Record "Expense Header"): Boolean
+    var
+        ExpenseLine: Record "Expense Line";
+        ExpenseUser: Record "Expense User";
+        ApprovalMgt: Codeunit "Expense Approval Management";
+        FeatureTelemetry: Codeunit "Feature Telemetry";
+        ErrorMsg: Text;
+        TotalAmount: Decimal;
+    begin
+        if ExpenseHeader.Status = ExpenseHeader.Status::Released then
+            Error(DocumentAlreadyReleasedErr, ExpenseHeader."No.");
+
+        ValidateApprover(ExpenseHeader);
+
+        ExpenseLine.SetRange("Document No.", ExpenseHeader."No.");
+        if ExpenseLine.FindSet() then
+            repeat
+                ValidateExpenseLine(ExpenseLine);
+                TotalAmount += ExpenseLine.Amount;
+            until ExpenseLine.Next() = 0;
+
+        if not CheckApprovalLimits(ExpenseHeader, TotalAmount) then
+            Error(InsufficientApprovalLimitErr, ExpenseHeader."No.");
+
+        ExpenseHeader.Status := ExpenseHeader.Status::Released;
+        ExpenseHeader."Released Date" := Today;
+        ExpenseHeader."Released Time" := Time;
+        ExpenseHeader."Released By" := UserId;
+
+        if ExpenseHeader.Modify(true) then begin
+            FeatureTelemetry.LogUsage('0000EA1', 'Expense Agent', 'Document Released', GetTelemetryDimensions(ExpenseHeader));
+
+            ApprovalMgt.SendReleaseNotification(ExpenseHeader);
+
+            Message(ExpenseDocumentReleasedMsg, ExpenseHeader."No.");
+            exit(true);
+        end else begin
+            Error(ExpenseDocumentReleaseFailedErr, ExpenseHeader."No.");
+        end;
+    end;
+
+    local procedure ValidateApprover(ExpenseHeader: Record "Expense Header")
+    var
+        ExpenseUser: Record "Expense User";
+    begin
+        if IsNullGuid(ExpenseHeader."Approver User ID") then
+            Error(MissingApproverErr, ExpenseHeader."No.");
+
+        ExpenseUser.SetRange("User Security ID", ExpenseHeader."Approver User ID");
+        ExpenseUser.SetRange("Is Active", true);
+        ExpenseUser.SetRange("Allow Expense Approval", true);
+
+        if not ExpenseUser.FindFirst() then
+            Error(MissingApproverErr, ExpenseHeader."No.");
+    end;
+
+    local procedure ValidateExpenseLine(ExpenseLine: Record "Expense Line")
+    var
+        ErrorMsg: Text;
+    begin
+        ExpenseLine.TestField("Expense Date");
+        ExpenseLine.TestField(Amount);
+        ExpenseLine.TestField("Expense Type Code");
+
+        if (ExpenseLine."Receipt No." <> '') or (ExpenseLine."Receipt Date" <> 0D) or (ExpenseLine."Merchant Name" <> '') then begin
+            if (ExpenseLine."Receipt No." = '') or (ExpenseLine."Receipt Date" = 0D) or (ExpenseLine."Merchant Name" = '') then begin
+                ErrorMsg := StrSubstNo(InvalidReceiptDataErr,
+                                     ExpenseLine."Line No.",
+                                     ExpenseLine."Receipt No.",
+                                     ExpenseLine."Expense Date",
+                                     ExpenseLine."Merchant Name");
+                Error(ErrorMsg);
+            end;
+
+            if ExpenseLine."Receipt Date" <> ExpenseLine."Expense Date" then begin
+                ErrorMsg := 'Receipt date (%1) does not match expense date (%2) for line %3';
+                Error(ErrorMsg, ExpenseLine."Receipt Date", ExpenseLine."Expense Date", ExpenseLine."Line No.");
+            end;
+        end;
+
+        if ExpenseLine.Amount <= 0 then
+            Error('Expense amount must be greater than zero for line %1', ExpenseLine."Line No.");
+
+        if ExpenseLine."Currency Code" <> '' then
+            ValidateCurrency(ExpenseLine);
+    end;
+
+    local procedure ValidateCurrency(ExpenseLine: Record "Expense Line")
+    var
+        Currency: Record Currency;
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+    begin
+        if not Currency.Get(ExpenseLine."Currency Code") then
+            Error('Currency %1 does not exist for line %2', ExpenseLine."Currency Code", ExpenseLine."Line No.");
+
+        if ExpenseLine."Exchange Rate" <= 0 then begin
+            CurrencyExchangeRate.SetRange("Currency Code", ExpenseLine."Currency Code");
+            CurrencyExchangeRate.SetFilter("Starting Date", '<=%1', ExpenseLine."Expense Date");
+            if not CurrencyExchangeRate.FindLast() then
+                Error('No exchange rate found for currency %1 on %2', ExpenseLine."Currency Code", ExpenseLine."Expense Date");
+        end;
+    end;
+
+    local procedure CheckApprovalLimits(ExpenseHeader: Record "Expense Header"; TotalAmount: Decimal): Boolean
+    var
+        ExpenseUser: Record "Expense User";
+        GeneralLedgerSetup: Record "General Ledger Setup";
+    begin
+        ExpenseUser.SetRange("User Security ID", ExpenseHeader."Approver User ID");
+        if not ExpenseUser.FindFirst() then
+            exit(false);
+
+        GeneralLedgerSetup.Get();
+
+        if ExpenseHeader."Currency Code" <> '' then
+            TotalAmount := ConvertToLCY(TotalAmount, ExpenseHeader."Currency Code", ExpenseHeader."Document Date");
+
+        if ExpenseUser."Approval Limit" = 0 then
+            exit(true);
+
+        exit(TotalAmount <= ExpenseUser."Approval Limit");
+    end;
+
+    local procedure ConvertToLCY(Amount: Decimal; CurrencyCode: Code[10]; DocumentDate: Date): Decimal
+    var
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+    begin
+        exit(CurrencyExchangeRate.ExchangeAmtFCYToLCY(DocumentDate, CurrencyCode, Amount,
+                                                     CurrencyExchangeRate.ExchangeRate(DocumentDate, CurrencyCode)));
+    end;
+
+    local procedure GetTelemetryDimensions(ExpenseHeader: Record "Expense Header"): Dictionary of [Text, Text]
+    var
+        Dimensions: Dictionary of [Text, Text];
+    begin
+        Dimensions.Add('DocumentNo', ExpenseHeader."No.");
+        Dimensions.Add('EmployeeNo', ExpenseHeader."Employee No.");
+        Dimensions.Add('CurrencyCode', ExpenseHeader."Currency Code");
+        Dimensions.Add('TotalAmount', Format(ExpenseHeader."Total Amount"));
+        Dimensions.Add('CompanyName', CompanyName);
+        exit(Dimensions);
+    end;
+
+    procedure ReopenExpenseDocument(var ExpenseHeader: Record "Expense Header")
+    var
+        FeatureTelemetry: Codeunit "Feature Telemetry";
+    begin
+        if ExpenseHeader.Status <> ExpenseHeader.Status::Released then
+            Error('Document %1 is not released and cannot be reopened.', ExpenseHeader."No.");
+
+        ExpenseHeader.Status := ExpenseHeader.Status::Open;
+        Clear(ExpenseHeader."Released Date");
+        Clear(ExpenseHeader."Released Time");
+        Clear(ExpenseHeader."Released By");
+
+        ExpenseHeader.Modify(true);
+
+        FeatureTelemetry.LogUsage('0000EA2', 'Expense Agent', 'Document Reopened', GetTelemetryDimensions(ExpenseHeader));
+
+        Message('Expense document %1 has been reopened.', ExpenseHeader."No.");
+    end;
+
+    [IntegrationEvent(false, false)]
+    local procedure OnBeforeReleaseExpenseDocument(var ExpenseHeader: Record "Expense Header"; var IsHandled: Boolean)
+    begin
+    end;
+
+    [IntegrationEvent(false, false)]
+    local procedure OnAfterReleaseExpenseDocument(var ExpenseHeader: Record "Expense Header")
+    begin
+    end;
+}
