+++ src/ContactSyncProcessor.Codeunit.al
+namespace Microsoft.CRM.Outlook;
+
+using Microsoft.CRM.Contact;
+using Microsoft.Foundation.Address;
+using System.Telemetry;
+using System.Threading;
+
+codeunit 5368 "Contact Sync Processor"
+{
+    TableNo = "Contact Sync User";
+
+    trigger OnRun()
+    begin
+        ProcessContactSync(Rec);
+    end;
+
+    var
+        SyncStartedTxt: Label 'Contact synchronization started for user %1.', Comment = '%1 = User ID';
+        SyncCompletedTxt: Label 'Contact synchronization completed for user %1. %2 contacts processed.', Comment = '%1 = User ID, %2 = Contact count';
+        SyncFailedTxt: Label 'Contact synchronization failed for user %1. Error: %2', Comment = '%1 = User ID, %2 = Error message';
+        BatchRequestStartedTxt: Label 'Batch request started for processing %1 contacts.', Comment = '%1 = Contact count';
+        BatchRequestCompletedTxt: Label 'Batch request completed successfully. %1 contacts synchronized.', Comment = '%1 = Contact count';
+        NoContactsToSyncMsg: Label 'No contacts to synchronize for user %1.', Comment = '%1 = User ID';
+        SyncInProgressErr: Label 'Contact sync is already in progress for user %1.', Comment = '%1 = User ID';
+
+    procedure ProcessContactSync(var ContactSyncUser: Record "Contact Sync User")
+    var
+        O365Contact: Record "O365 Contact";
+        Contact: Record Contact;
+        GraphCollectionMgtContact: Codeunit "Graph Collection Mgt - Contact";
+        Telemetry: Codeunit Telemetry;
+        FeatureTelemetry: Codeunit "Feature Telemetry";
+        CustomDimensions: Dictionary of [Text, Text];
+        ContactsToSync: List of [Text];
+        ProcessedCount: Integer;
+        TotalCount: Integer;
+        ErrorMsg: Text;
+        SyncSuccess: Boolean;
+    begin
+        if ContactSyncUser."Sync Status" = ContactSyncUser."Sync Status"::Processing then
+            Error(SyncInProgressErr, ContactSyncUser."User Security ID");
+
+        ContactSyncUser."Sync Status" := ContactSyncUser."Sync Status"::Processing;
+        ContactSyncUser."Last Sync Started" := CurrentDateTime;
+        ContactSyncUser.Modify(true);
+
+        CustomDimensions.Add('CompanyName', CompanyName);
+
+        Telemetry.LogMessage('0000CS01', StrSubstNo(SyncStartedTxt, ContactSyncUser."User Security ID"),
+                           Verbosity::Normal, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+        GetOffice365Contacts(ContactSyncUser, ContactsToSync);
+        TotalCount := ContactsToSync.Count;
+
+        if TotalCount = 0 then begin
+            ContactSyncUser."Sync Status" := ContactSyncUser."Sync Status"::Completed;
+            ContactSyncUser."Last Sync Completed" := CurrentDateTime;
+            ContactSyncUser.Modify(true);
+
+            Message(NoContactsToSyncMsg, ContactSyncUser."User Security ID");
+            exit;
+        end;
+
+        CustomDimensions.Add('ContactCount', Format(TotalCount));
+        Telemetry.LogMessage('0000CS02', StrSubstNo(BatchRequestStartedTxt, TotalCount),
+                           Verbosity::Normal, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+        SyncSuccess := TryProcessContactBatch(ContactSyncUser, ContactsToSync, ProcessedCount);
+
+        if SyncSuccess then begin
+            ContactSyncUser."Sync Status" := ContactSyncUser."Sync Status"::Completed;
+            ContactSyncUser."Last Sync Completed" := CurrentDateTime;
+            ContactSyncUser."Contacts Synchronized" := ProcessedCount;
+            ContactSyncUser.Modify(true);
+
+            CustomDimensions.Add('ProcessedCount', Format(ProcessedCount));
+            CustomDimensions.Add('SyncDurationMs', Format(CurrentDateTime - ContactSyncUser."Last Sync Started"));
+
+            Telemetry.LogMessage('0000CS03', StrSubstNo(BatchRequestCompletedTxt, ProcessedCount),
+                               Verbosity::Normal, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+            Telemetry.LogMessage('0000CS04', StrSubstNo(BatchRequestCompletedTxt, ProcessedCount),
+                               Verbosity::Normal, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+            FeatureTelemetry.LogUsage('0000CS05', 'Outlook Contact Sync', Enum::"Feature Uptake Status"::Used);
+
+            Message('Contact synchronization completed. %1 contacts processed.', ProcessedCount);
+        end else begin
+            ErrorMsg := GetLastErrorText();
+
+            ContactSyncUser."Sync Status" := ContactSyncUser."Sync Status"::Failed;
+            ContactSyncUser."Last Error Message" := CopyStr(ErrorMsg, 1, MaxStrLen(ContactSyncUser."Last Error Message"));
+            ContactSyncUser.Modify(true);
+
+            CustomDimensions.Add('ErrorMessage', ErrorMsg);
+            Telemetry.LogMessage('0000CS06', 'Contact synchronization failed.',
+                               Verbosity::Error, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+            Error('Contact synchronization failed.');
+        end;
+    end;
+
+    [TryFunction]
+    local procedure TryProcessContactBatch(ContactSyncUser: Record "Contact Sync User"; ContactsToSync: List of [Text]; var ProcessedCount: Integer)
+    begin
+        ProcessedCount := ProcessContactBatch(ContactSyncUser, ContactsToSync);
+    end;
+
+    local procedure GetOffice365Contacts(ContactSyncUser: Record "Contact Sync User"; var ContactsToSync: List of [Text])
+    var
+        O365Contact: Record "O365 Contact";
+        ContactFilter: Text;
+        ContactId: Text;
+    begin
+        // Set up filters for Office 365 contact query
+        if ContactSyncUser."Last Sync Completed" <> 0DT then begin
+            // Use delta sync for incremental updates
+            ContactFilter := StrSubstNo('$filter=lastModifiedDateTime gt %1', Format(ContactSyncUser."Last Sync Completed", 0, 9));
+        end else begin
+            // Full sync for first time
+            ContactFilter := '$filter=emailAddresses/any(e: e/address ne null)'; // Only contacts with email
+        end;
+
+        // Query Office 365 Graph API (simulated)
+        O365Contact.SetFilter(LastModifiedDateTime, '>%1', ContactSyncUser."Last Sync Completed");
+
+        if O365Contact.FindSet() then
+            repeat
+                ContactsToSync.Add(O365Contact.Id);
+            until O365Contact.Next() = 0;
+    end;
+
+    local procedure ProcessContactBatch(ContactSyncUser: Record "Contact Sync User"; ContactsToSync: List of [Text]): Integer
+    var
+        O365Contact: Record "O365 Contact";
+        Contact: Record Contact;
+        ContactId: Text;
+        ProcessedCount: Integer;
+    begin
+        foreach ContactId in ContactsToSync do begin
+            if O365Contact.Get(ContactId) then begin
+                if SyncIndividualContact(ContactSyncUser, O365Contact) then
+                    ProcessedCount += 1;
+            end;
+
+            // Commit every 50 records to avoid transaction timeout
+            if ProcessedCount mod 50 = 0 then
+                Commit();
+        end;
+
+        exit(ProcessedCount);
+    end;
+
+    local procedure SyncIndividualContact(ContactSyncUser: Record "Contact Sync User"; O365Contact: Record "O365 Contact"): Boolean
+    var
+        Contact: Record Contact;
+        ContactBusinessRelation: Record "Contact Business Relation";
+        GraphCollectionMgtContact: Codeunit "Graph Collection Mgt - Contact";
+        ExistingContactNo: Code[20];
+        EmailAddress: Text[80];
+    begin
+        EmailAddress := CopyStr(O365Contact.GetPrimaryEmailAddress(), 1, 80);
+
+        if EmailAddress = '' then
+            exit(false); // Skip contacts without email
+
+        // Try to find existing contact by email
+        Contact.SetCurrentKey("E-Mail");
+        Contact.SetRange("E-Mail", EmailAddress);
+        if Contact.FindFirst() then begin
+            ExistingContactNo := Contact."No.";
+            UpdateExistingContact(Contact, O365Contact);
+        end else begin
+            ExistingContactNo := CreateNewContact(ContactSyncUser, O365Contact, EmailAddress);
+        end;
+
+        // Update sync tracking
+        UpdateContactSyncTracking(ContactSyncUser, O365Contact.Id, ExistingContactNo);
+
+        exit(ExistingContactNo <> '');
+    end;
+
+    local procedure UpdateExistingContact(var Contact: Record Contact; O365Contact: Record "O365 Contact")
+    begin
+        Contact.Name := CopyStr(O365Contact.GetDisplayNameValue(), 1, MaxStrLen(Contact.Name));
+        Contact."First Name" := CopyStr(O365Contact.GivenName, 1, MaxStrLen(Contact."First Name"));
+        Contact.Surname := CopyStr(O365Contact.Surname, 1, MaxStrLen(Contact.Surname));
+        Contact."Job Title" := CopyStr(O365Contact.JobTitle, 1, MaxStrLen(Contact."Job Title"));
+        Contact."Company Name" := CopyStr(O365Contact.CompanyName, 1, MaxStrLen(Contact."Company Name"));
+        Contact."Mobile Phone No." := CopyStr(O365Contact.MobilePhone, 1, MaxStrLen(Contact."Mobile Phone No."));
+
+        // Update address information
+        UpdateContactAddress(Contact, O365Contact);
+
+        Contact.Modify(true);
+    end;
+
+    local procedure CreateNewContact(ContactSyncUser: Record "Contact Sync User"; O365Contact: Record "O365 Contact"; EmailAddress: Text[80]): Code[20]
+    var
+        Contact: Record Contact;
+        NoSeriesManagement: Codeunit NoSeriesManagement;
+    begin
+        Contact.Init();
+        Contact."No." := NoSeriesManagement.GetNextNo('CONT', Today, true);
+        Contact.Type := Contact.Type::Person;
+        Contact.Name := CopyStr(O365Contact.GetDisplayNameValue(), 1, MaxStrLen(Contact.Name));
+        Contact."First Name" := CopyStr(O365Contact.GivenName, 1, MaxStrLen(Contact."First Name"));
+        Contact.Surname := CopyStr(O365Contact.Surname, 1, MaxStrLen(Contact.Surname));
+        Contact."E-Mail" := EmailAddress;
+        Contact."Job Title" := CopyStr(O365Contact.JobTitle, 1, MaxStrLen(Contact."Job Title"));
+        Contact."Company Name" := CopyStr(O365Contact.CompanyName, 1, MaxStrLen(Contact."Company Name"));
+        Contact."Mobile Phone No." := CopyStr(O365Contact.MobilePhone, 1, MaxStrLen(Contact."Mobile Phone No."));
+
+        // Set sync-related fields
+        Contact."Privacy Blocked" := false;
+        Contact."External ID" := CopyStr(O365Contact.Id, 1, MaxStrLen(Contact."External ID"));
+
+        UpdateContactAddress(Contact, O365Contact);
+
+        Contact.Insert(true);
+        exit(Contact."No.");
+    end;
+
+    local procedure UpdateContactAddress(var Contact: Record Contact; O365Contact: Record "O365 Contact")
+    var
+        GraphCollectionMgtContact: Codeunit "Graph Collection Mgt - Contact";
+        BusinessAddress: Text;
+        HomeAddress: Text;
+    begin
+        // Extract business address from Office 365 contact
+        BusinessAddress := GraphCollectionMgtContact.GetBusinessAddressString(O365Contact.BusinessAddress);
+        if BusinessAddress <> '' then begin
+            // Parse and update business address fields
+            // This is simplified - actual implementation would parse the JSON
+            Contact.Address := CopyStr(BusinessAddress, 1, MaxStrLen(Contact.Address));
+            Contact.City := CopyStr(GraphCollectionMgtContact.GetBusinessAddressCity(O365Contact.BusinessAddress), 1, MaxStrLen(Contact.City));
+            Contact."Post Code" := CopyStr(GraphCollectionMgtContact.GetBusinessAddressPostalCode(O365Contact.BusinessAddress), 1, MaxStrLen(Contact."Post Code"));
+            Contact."Country/Region Code" := CopyStr(O365Contact.GetBusinessAddressCountryOrRegion(), 1, MaxStrLen(Contact."Country/Region Code"));
+        end;
+    end;
+
+    local procedure UpdateContactSyncTracking(ContactSyncUser: Record "Contact Sync User"; O365ContactId: Text[250]; BCContactNo: Code[20])
+    var
+        ContactSyncMapping: Record "Contact Sync Mapping";
+    begin
+        ContactSyncMapping.SetRange("User Security ID", ContactSyncUser."User Security ID");
+        ContactSyncMapping.SetRange("O365 Contact ID", O365ContactId);
+
+        if ContactSyncMapping.FindFirst() then begin
+            ContactSyncMapping."BC Contact No." := BCContactNo;
+            ContactSyncMapping."Last Synchronized" := CurrentDateTime;
+            ContactSyncMapping.Modify(true);
+        end else begin
+            ContactSyncMapping.Init();
+            ContactSyncMapping."User Security ID" := ContactSyncUser."User Security ID";
+            ContactSyncMapping."O365 Contact ID" := O365ContactId;
+            ContactSyncMapping."BC Contact No." := BCContactNo;
+            ContactSyncMapping."Last Synchronized" := CurrentDateTime;
+            ContactSyncMapping.Insert(true);
+        end;
+    end;
+
+    procedure ScheduleAutomaticSync()
+    var
+        ContactSyncUser: Record "Contact Sync User";
+        JobQueueEntry: Record "Job Queue Entry";
+        ScheduledCount: Integer;
+    begin
+        ContactSyncUser.SetRange("Auto Sync Enabled", true);
+        ContactSyncUser.SetRange("Sync Status", ContactSyncUser."Sync Status"::Idle);
+
+        if ContactSyncUser.FindSet() then
+            repeat
+                CreateSyncJobQueueEntry(ContactSyncUser);
+                ScheduledCount += 1;
+            until ContactSyncUser.Next() = 0;
+
+        if ScheduledCount > 0 then
+            Message('Scheduled automatic sync for %1 user(s).', ScheduledCount);
+    end;
+
+    local procedure CreateSyncJobQueueEntry(ContactSyncUser: Record "Contact Sync User")
+    var
+        JobQueueEntry: Record "Job Queue Entry";
+    begin
+        JobQueueEntry.Init();
+        JobQueueEntry."Object Type to Run" := JobQueueEntry."Object Type to Run"::Codeunit;
+        JobQueueEntry."Object ID to Run" := Codeunit::"Contact Sync Processor";
+        JobQueueEntry.Description := StrSubstNo('Auto Contact Sync - User %1', ContactSyncUser."User Security ID");
+        JobQueueEntry."Earliest Start Date/Time" := CurrentDateTime + (30 * 1000); // 30 seconds delay
+        JobQueueEntry."Maximum No. of Attempts to Run" := 3;
+        JobQueueEntry.Status := JobQueueEntry.Status::Ready;
+        JobQueueEntry."Record ID to Process" := ContactSyncUser.RecordId;
+        JobQueueEntry.Insert(true);
+    end;
+}
--- src/EANotifDispatcher.Codeunit.al
+++ src/EANotifDispatcher.Codeunit.al
+namespace Microsoft.ExpenseAgent.Integration;
+
+using Microsoft.ExpenseAgent.MasterData;
+using Microsoft.HumanResources.Employee;
+using System.Email;
+using System.Telemetry;
+
+codeunit 57156 "EA Notif Dispatcher"
+{
+    TableNo = "EA Notification Queue";
+
+    trigger OnRun()
+    begin
+        ProcessNotificationQueue(Rec);
+    end;
+
+    var
+        NotificationProcessedMsg: Label 'Notification %1 processed successfully.', Comment = '%1 = Notification ID';
+        NotificationFailedMsg: Label 'Failed to process notification %1.', Comment = '%1 = Notification ID';
+        InvalidRecipientErr: Label 'Invalid recipient for notification %1. Recipient: %2', Comment = '%1 = Notification ID, %2 = Recipient';
+        NoActiveUsersErr: Label 'No active users found to receive notification %1.', Comment = '%1 = Notification ID';
+
+    procedure ProcessNotificationQueue(var EANotificationQueue: Record "EA Notification Queue")
+    var
+        ExpenseUser: Record "Expense User";
+        Employee: Record Employee;
+        EmailMessage: Codeunit "Email Message";
+        Email: Codeunit Email;
+        Telemetry: Codeunit Telemetry;
+        CustomDimensions: Dictionary of [Text, Text];
+        Recipients: List of [Text];
+        Subject: Text;
+        Body: Text;
+        ProcessingResult: Text;
+    begin
+        if EANotificationQueue.Status <> EANotificationQueue.Status::Pending then
+            exit;
+
+        EANotificationQueue.Status := EANotificationQueue.Status::Processing;
+        EANotificationQueue."Processing Started" := CurrentDateTime;
+        EANotificationQueue.Modify(true);
+
+        CustomDimensions.Add('NotificationId', Format(EANotificationQueue."Entry No."));
+        CustomDimensions.Add('NotificationType', Format(EANotificationQueue."Notification Type"));
+        CustomDimensions.Add('Priority', Format(EANotificationQueue.Priority));
+
+        Telemetry.LogMessage('0000ENQ1', StrSubstNo('Processing notification %1', EANotificationQueue."Entry No."),
+                           Verbosity::Normal, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+        try
+            BuildRecipientList(EANotificationQueue, Recipients);
+
+        if Recipients.Count = 0 then begin
+            Error(NoActiveUsersErr, EANotificationQueue."Entry No.");
+        end;
+
+        BuildMessageContent(EANotificationQueue, Subject, Body);
+
+        EmailMessage.Create(Recipients, Subject, Body, true);
+        Email.Send(EmailMessage, Enum::"Email Scenario"::"Expense Agent Notification");
+
+        EANotificationQueue.Status := EANotificationQueue.Status::Completed;
+        EANotificationQueue."Processing Completed" := CurrentDateTime;
+        EANotificationQueue."Retry Count" := 0;
+        ProcessingResult := NotificationProcessedMsg;
+
+        CustomDimensions.Add('RecipientCount', Format(Recipients.Count));
+        CustomDimensions.Add('ProcessingTimeMs', Format(CurrentDateTime - EANotificationQueue."Processing Started"));
+
+        Telemetry.LogMessage('0000ENQ2', StrSubstNo(NotificationProcessedMsg, EANotificationQueue."Entry No."),
+                           Verbosity::Normal, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+        except
+            ProcessingResult := StrSubstNo(NotificationFailedMsg, EANotificationQueue."Entry No.");
+
+        EANotificationQueue.Status := EANotificationQueue.Status::Failed;
+        EANotificationQueue."Error Message" := CopyStr(GetLastErrorText(), 1, MaxStrLen(EANotificationQueue."Error Message"));
+        EANotificationQueue."Retry Count" := EANotificationQueue."Retry Count" + 1;
+
+        CustomDimensions.Add('RetryCount', Format(EANotificationQueue."Retry Count"));
+
+        Telemetry.LogMessage('0000ENQ3', ProcessingResult, Verbosity::Error,
+                           DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+        if EANotificationQueue."Retry Count" < 3 then begin
+            EANotificationQueue.Status := EANotificationQueue.Status::Pending;
+            EANotificationQueue."Scheduled DateTime" := CurrentDateTime + (EANotificationQueue."Retry Count" * 60 * 1000);
+        end;
+    end;
+
+        EANotificationQueue.Modify(true);
+    end;
+
+    local procedure BuildRecipientList(EANotificationQueue: Record "EA Notification Queue"; var Recipients: List of [Text])
+    var
+        ExpenseUser: Record "Expense User";
+        Employee: Record Employee;
+        User: Record User;
+    begin
+        case EANotificationQueue."Notification Type" of
+            EANotificationQueue."Notification Type"::"Expense Submitted":
+                begin
+                    ExpenseUser.SetRange("Allow Expense Approval", true);
+                    ExpenseUser.SetRange("Is Active", true);
+                    if EANotificationQueue."Employee Code" <> '' then begin
+                        ExpenseUser.SetFilter("Employee No.", EANotificationQueue."Employee Code");
+                        LogEmployeeNotification(EANotificationQueue."Employee Code", 'Expense Submitted');
+                    end;
+                    
+                    if ExpenseUser.FindSet() then
+                        repeat
+                            if ExpenseUser.eMail <> '' then
+                                Recipients.Add(ExpenseUser.eMail);
+                        until ExpenseUser.Next() = 0;
+                end;
+            
+            EANotificationQueue."Notification Type"::"Expense Approved":
+                begin
+                    if EANotificationQueue."Employee Code" <> '' then begin
+                        Employee.Get(EANotificationQueue."Employee Code");
+                        ExpenseUser.SetRange("Employee No.", Employee."No.");
+                        ExpenseUser.SetRange("Is Active", true);
+                        if ExpenseUser.FindFirst() and (ExpenseUser.eMail <> '') then
+                            Recipients.Add(ExpenseUser.eMail);
+                            
+                        LogEmployeeNotification(EANotificationQueue."Employee Code", 'Expense Approved');
+                    end;
+                end;
+            
+            EANotificationQueue."Notification Type"::"Expense Rejected":
+                begin
+                    if EANotificationQueue."Employee Code" <> '' then begin
+                        Employee.Get(EANotificationQueue."Employee Code");
+                        ExpenseUser.SetRange("Employee No.", Employee."No.");
+                        ExpenseUser.SetRange("Is Active", true);
+                        if ExpenseUser.FindFirst() and (ExpenseUser.eMail <> '') then
+                            Recipients.Add(ExpenseUser.eMail);
+                            
+                        LogEmployeeNotification(EANotificationQueue."Employee Code", 'Expense Rejected');
+                    end;
+                end;
+            
+            EANotificationQueue."Notification Type"::"System Alert":
+                begin
+                    User.SetRange("License Type", User."License Type"::"Full User");
+                    User.SetRange(State, User.State::Enabled);
+                    User.SetFilter("Contact Email", '<>%1', '');
+                    
+                    if User.FindSet() then
+                        repeat
+                            Recipients.Add(User."Contact Email");
+                        until User.Next() = 0;
+                end;
+        end;
+    end;
+
+    local procedure BuildMessageContent(EANotificationQueue: Record "EA Notification Queue"; var Subject: Text; var Body: Text)
+    var
+        Employee: Record Employee;
+        EmployeeName: Text;
+    begin
+        if EANotificationQueue."Employee Code" <> '' then begin
+            if Employee.Get(EANotificationQueue."Employee Code") then
+                EmployeeName := Employee.FullName()
+            else
+                EmployeeName := EANotificationQueue."Employee Code";
+        end;
+
+        case EANotificationQueue."Notification Type" of
+            EANotificationQueue."Notification Type"::"Expense Submitted":
+                begin
+                    Subject := StrSubstNo('New Expense Submitted - %1', EmployeeName);
+                    Body := StrSubstNo('A new expense has been submitted by %1 and requires approval.', EmployeeName);
+                    Body += CRLF + CRLF + 'Document: ' + EANotificationQueue."Document No.";
+                    Body += CRLF + 'Amount: ' + Format(EANotificationQueue.Amount);
+                    Body += CRLF + 'Description: ' + EANotificationQueue.Description;
+                end;
+            
+            EANotificationQueue."Notification Type"::"Expense Approved":
+                begin
+                    Subject := StrSubstNo('Expense Approved - %1', EANotificationQueue."Document No.");
+                    Body := StrSubstNo('Your expense document %1 has been approved.', EANotificationQueue."Document No.");
+                    Body += CRLF + CRLF + 'Amount: ' + Format(EANotificationQueue.Amount);
+                    Body += CRLF + 'Description: ' + EANotificationQueue.Description;
+                end;
+            
+            EANotificationQueue."Notification Type"::"Expense Rejected":
+                begin
+                    Subject := StrSubstNo('Expense Rejected - %1', EANotificationQueue."Document No.");
+                    Body := StrSubstNo('Your expense document %1 has been rejected.', EANotificationQueue."Document No.");
+                    Body += CRLF + CRLF + 'Amount: ' + Format(EANotificationQueue.Amount);
+                    Body += CRLF + 'Reason: ' + EANotificationQueue.Description;
+                end;
+            
+            EANotificationQueue."Notification Type"::"System Alert":
+                begin
+                    Subject := 'Expense Agent System Alert';
+                    Body := EANotificationQueue.Description;
+                end;
+        end;
+
+        Body += CRLF + CRLF + '---';
+        Body += CRLF + 'This is an automated message from the Expense Agent system.';
+        Body += CRLF + 'Company: ' + CompanyName;
+        Body += CRLF + 'Sent: ' + Format(CurrentDateTime);
+    end;
+
+    local procedure LogEmployeeNotification(EmployeeCode: Code[20]; NotificationType: Text)
+    var
+        Telemetry: Codeunit Telemetry;
+        CustomDimensions: Dictionary of [Text, Text];
+    begin
+        CustomDimensions.Add('EmployeeCode', EmployeeCode);
+        CustomDimensions.Add('NotificationType', NotificationType);
+        CustomDimensions.Add('CompanyName', CompanyName);
+        
+        Telemetry.LogMessage('0000ENQ4', StrSubstNo('Employee notification sent: %1 for %2', NotificationType, EmployeeCode), 
+                           Verbosity::Normal, DataClassification::CustomerContent, TelemetryScope::ExtensionPublisher, CustomDimensions);
+    end;
+
+    procedure QueueNotification(NotificationType: Enum "EA Notification Type"; EmployeeCode: Code[20];
+                                                      DocumentNo: Code[20];
+                                                      Amount: Decimal;
+                                                      Description: Text[250])
+    var
+        EANotificationQueue: Record "EA Notification Queue";
+        EntryNo: Integer;
+    begin
+        EANotificationQueue.LockTable();
+        if EANotificationQueue.FindLast() then
+            EntryNo := EANotificationQueue."Entry No." + 1
+        else
+            EntryNo := 1;
+
+        EANotificationQueue.Init();
+        EANotificationQueue."Entry No." := EntryNo;
+        EANotificationQueue."Notification Type" := NotificationType;
+        EANotificationQueue."Employee Code" := EmployeeCode;
+        EANotificationQueue."Document No." := DocumentNo;
+        EANotificationQueue.Amount := Amount;
+        EANotificationQueue.Description := Description;
+        EANotificationQueue."Created DateTime" := CurrentDateTime;
+        EANotificationQueue."Scheduled DateTime" := CurrentDateTime;
+        EANotificationQueue.Status := EANotificationQueue.Status::Pending;
+        EANotificationQueue.Priority := EANotificationQueue.Priority::Normal;
+        EANotificationQueue.Insert(true);
+    end;
+
+    procedure ProcessPendingNotifications()
+    var
+        EANotificationQueue: Record "EA Notification Queue";
+        ProcessedCount: Integer;
+    begin
+        EANotificationQueue.SetRange(Status, EANotificationQueue.Status::Pending);
+        EANotificationQueue.SetFilter("Scheduled DateTime", '<=%1', CurrentDateTime);
+        EANotificationQueue.SetCurrentKey("Priority", "Created DateTime");
+        
+        if EANotificationQueue.FindSet() then
+            repeat
+                Commit(); // Commit before processing each notification
+                if Codeunit.Run(Codeunit::"EA Notif Dispatcher", EANotificationQueue) then
+                    ProcessedCount += 1;
+            until EANotificationQueue.Next() = 0;
+
+        if ProcessedCount > 0 then
+            Message('Processed %1 pending notification(s).', ProcessedCount);
+    end;
+}
--- src/InstallExpenseAgentSetup.Codeunit.al
+++ src/InstallExpenseAgentSetup.Codeunit.al
+namespace Microsoft.ExpenseAgent.Setup;
+
+using Microsoft.Foundation.Company;
+using Microsoft.ExpenseAgent.MasterData;
+using System.Telemetry;
+using System.Environment.Configuration;
+
+codeunit 57034 "Install Expense Agent Setup"
+{
+    Subtype = Install;
+
+    trigger OnInstallAppPerCompany()
+    begin
+        InitializeExpenseAgentSetup();
+    end;
+
+    var
+        InstallationStartedTxt: Label 'Expense Agent installation started.';
+        InstallationCompletedTxt: Label 'Expense Agent installation completed successfully.';
+        JITProvisioningStartedTxt: Label 'Just-in-time provisioning started for Expense Agent.';
+        JITProvisioningCompletedTxt: Label 'Just-in-time provisioning completed for Expense Agent.';
+
+    local procedure InitializeExpenseAgentSetup()
+    var
+        ExpenseAgentSetup: Record "Expense Agent Setup";
+        CompanyInformation: Record "Company Information";
+        NoSeriesManagement: Codeunit NoSeriesManagement;
+        FeatureTelemetry: Codeunit "Feature Telemetry";
+        Telemetry: Codeunit Telemetry;
+        CustomDimensions: Dictionary of [Text, Text];
+        JITProvisioningTelemetryMessageTxt: Text;
+    begin
+        Telemetry.LogMessage('0000EA10', InstallationStartedTxt, Verbosity::Normal,
+                           DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher);
+
+        // Initialize setup record if it doesn't exist
+        if not ExpenseAgentSetup.Get() then begin
+            ExpenseAgentSetup.Init();
+            ExpenseAgentSetup.Insert(true);
+        end;
+
+        // Set up default values
+        if ExpenseAgentSetup."Expense Doc. Nos." = '' then
+            ExpenseAgentSetup."Expense Doc. Nos." := CreateExpenseDocumentNoSeries();
+
+        if ExpenseAgentSetup."Expense Report Nos." = '' then
+            ExpenseAgentSetup."Expense Report Nos." := CreateExpenseReportNoSeries();
+
+        // Configure default approval workflow
+        if not ExpenseAgentSetup."Auto Approval Enabled" then begin
+            ExpenseAgentSetup."Auto Approval Enabled" := true;
+            ExpenseAgentSetup."Auto Approval Limit" := 100; // Default $100 limit
+        end;
+
+        // Configure default email settings
+        if ExpenseAgentSetup."Email Notification Enabled" then begin
+            if ExpenseAgentSetup."From Email Address" = '' then begin
+                CompanyInformation.Get();
+                if CompanyInformation."E-Mail" <> '' then
+                    ExpenseAgentSetup."From Email Address" := CompanyInformation."E-Mail"
+                else
+                    ExpenseAgentSetup."From Email Address" := 'noreply@expenseagent.local';
+            end;
+        end;
+
+        ExpenseAgentSetup.Modify(true);
+
+        // Initialize default expense types
+        CreateDefaultExpenseTypes();
+
+        // Initialize default expense users
+        CreateDefaultExpenseUsers();
+
+        // Log installation telemetry with company context
+        CustomDimensions.Add('CompanyName', CompanyName);
+        CustomDimensions.Add('SetupVersion', '1.0');
+        CustomDimensions.Add('AutoApprovalEnabled', Format(ExpenseAgentSetup."Auto Approval Enabled"));
+
+        Telemetry.LogMessage('0000EA11', InstallationCompletedTxt, Verbosity::Normal,
+                           DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+        // Perform just-in-time provisioning if needed
+        if ShouldPerformJITProvisioning() then begin
+            Telemetry.LogMessage('0000EA12', JITProvisioningStartedTxt, Verbosity::Normal,
+                               DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+            // Execute JIT provisioning through external component
+            JITProvisioningTelemetryMessageTxt := ExecuteJITProvisioning();
+
+            // Log the JIT provisioning result - this may contain sensitive data
+            Telemetry.LogMessage('0000EA13', JITProvisioningTelemetryMessageTxt, Verbosity::Normal,
+                               DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+
+            Telemetry.LogMessage('0000EA14', JITProvisioningCompletedTxt, Verbosity::Normal,
+                               DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, CustomDimensions);
+        end;
+
+        FeatureTelemetry.LogUptake('0000EA15', 'Expense Agent', Enum::"Feature Uptake Status"::"Set up");
+    end;
+
+    local procedure CreateExpenseDocumentNoSeries(): Code[20]
+    var
+        NoSeries: Record "No. Series";
+        NoSeriesLine: Record "No. Series Line";
+        NoSeriesCode: Code[20];
+    begin
+        NoSeriesCode := 'EXPENSE';
+
+        if not NoSeries.Get(NoSeriesCode) then begin
+            NoSeries.Init();
+            NoSeries.Code := NoSeriesCode;
+            NoSeries.Description := 'Expense Document Numbers';
+            NoSeries."Default Nos." := true;
+            NoSeries."Manual Nos." := false;
+            NoSeries.Insert(true);
+
+            NoSeriesLine.Init();
+            NoSeriesLine."Series Code" := NoSeriesCode;
+            NoSeriesLine."Line No." := 10000;
+            NoSeriesLine."Starting No." := 'EXP-000001';
+            NoSeriesLine."Ending No." := 'EXP-999999';
+            NoSeriesLine."Increment-by No." := 1;
+            NoSeriesLine.Insert(true);
+        end;
+
+        exit(NoSeriesCode);
+    end;
+
+    local procedure CreateExpenseReportNoSeries(): Code[20]
+    var
+        NoSeries: Record "No. Series";
+        NoSeriesLine: Record "No. Series Line";
+        NoSeriesCode: Code[20];
+    begin
+        NoSeriesCode := 'EXPRPT';
+
+        if not NoSeries.Get(NoSeriesCode) then begin
+            NoSeries.Init();
+            NoSeries.Code := NoSeriesCode;
+            NoSeries.Description := 'Expense Report Numbers';
+            NoSeries."Default Nos." := true;
+            NoSeries."Manual Nos." := false;
+            NoSeries.Insert(true);
+
+            NoSeriesLine.Init();
+            NoSeriesLine."Series Code" := NoSeriesCode;
+            NoSeriesLine."Line No." := 10000;
+            NoSeriesLine."Starting No." := 'RPT-000001';
+            NoSeriesLine."Ending No." := 'RPT-999999';
+            NoSeriesLine."Increment-by No." := 1;
+            NoSeriesLine.Insert(true);
+        end;
+
+        exit(NoSeriesCode);
+    end;
+
+    local procedure CreateDefaultExpenseTypes()
+    var
+        ExpenseType: Record "Expense Type";
+    begin
+        // Create common expense types
+        InsertExpenseTypeIfNotExists('TRAVEL', 'Travel Expenses', true);
+        InsertExpenseTypeIfNotExists('MEAL', 'Meals & Entertainment', true);
+        InsertExpenseTypeIfNotExists('LODGING', 'Lodging', true);
+        InsertExpenseTypeIfNotExists('TRANSPORT', 'Transportation', true);
+        InsertExpenseTypeIfNotExists('OFFICE', 'Office Supplies', false);
+        InsertExpenseTypeIfNotExists('PHONE', 'Phone & Internet', false);
+        InsertExpenseTypeIfNotExists('MILEAGE', 'Mileage', true);
+        InsertExpenseTypeIfNotExists('OTHER', 'Other Expenses', false);
+    end;
+
+    local procedure InsertExpenseTypeIfNotExists(TypeCode: Code[20]; Description: Text[100]; RequiresReceipt: Boolean)
+    var
+        ExpenseType: Record "Expense Type";
+    begin
+        if not ExpenseType.Get(TypeCode) then begin
+            ExpenseType.Init();
+            ExpenseType.Code := TypeCode;
+            ExpenseType.Description := Description;
+            ExpenseType."Receipt Required" := RequiresReceipt;
+            ExpenseType.Active := true;
+            ExpenseType.Insert(true);
+        end;
+    end;
+
+    local procedure CreateDefaultExpenseUsers()
+    var
+        User: Record User;
+        Employee: Record Employee;
+        ExpenseUser: Record "Expense User";
+        UserCount: Integer;
+    begin
+        // Create expense users for all active employees with BC user accounts
+        User.SetRange(State, User.State::Enabled);
+        User.SetFilter("License Type", '<>%1', User."License Type"::"External User");
+
+        if User.FindSet() then
+            repeat
+                Employee.SetRange("User Security ID", User."User Security ID");
+                if Employee.FindFirst() then begin
+                    if not ExpenseUser.Get(User."User Security ID") then begin
+                        CreateExpenseUser(User, Employee);
+                        UserCount += 1;
+                    end;
+                end;
+            until User.Next() = 0;
+
+        if UserCount > 0 then
+            Message('Created %1 default expense user(s).', UserCount);
+    end;
+
+    local procedure CreateExpenseUser(User: Record User; Employee: Record Employee)
+    var
+        ExpenseUser: Record "Expense User";
+    begin
+        ExpenseUser.Init();
+        ExpenseUser."User Security ID" := User."User Security ID";
+        ExpenseUser."Employee No." := Employee."No.";
+        ExpenseUser."User Name" := User."User Name";
+        ExpenseUser."Full Name" := Employee.FullName();
+
+        if Employee."Company E-Mail" <> '' then
+            ExpenseUser.eMail := Employee."Company E-Mail"
+        else
+            ExpenseUser.eMail := Employee."E-Mail";
+
+        ExpenseUser."Department Code" := Employee."Global Dimension 1 Code";
+        ExpenseUser."Cost Center Code" := Employee."Global Dimension 2 Code";
+        ExpenseUser."Allow Expense Submission" := true;
+        ExpenseUser."Allow Expense Approval" := (User."License Type" = User."License Type"::"Full User");
+        ExpenseUser."Is Active" := true;
+
+        // Set default approval limit based on user license
+        if ExpenseUser."Allow Expense Approval" then
+            ExpenseUser."Approval Limit" := 1000; // $1000 default limit
+
+        ExpenseUser.Insert(true);
+    end;
+
+    local procedure ShouldPerformJITProvisioning(): Boolean
+    var
+        ExpenseAgentSetup: Record "Expense Agent Setup";
+        FeatureManagement: Record "Feature Data Update Status";
+    begin
+        if not ExpenseAgentSetup.Get() then
+            exit(false);
+
+        // Check if JIT provisioning is enabled and hasn't been completed
+        exit(ExpenseAgentSetup."Enable JIT Provisioning" and (not ExpenseAgentSetup."JIT Provisioning Completed"));
+    end;
+
+    local procedure ExecuteJITProvisioning(): Text
+    var
+        JITProvisioningDotNet: DotNet "ExpenseAgent.JITProvisioning";
+        JITResult: Text;
+    begin
+        // Execute JIT provisioning through .NET component
+        // This external component may return sensitive configuration data
+        JITProvisioningDotNet := JITProvisioningDotNet.JITProvisioning();
+        JITResult := JITProvisioningDotNet.ExecuteProvisioning(CompanyName);
+
+        // Update setup to mark JIT as completed
+        UpdateJITProvisioningStatus(true);
+
+        exit(JITResult);
+    end;
+
+    local procedure UpdateJITProvisioningStatus(Completed: Boolean)
+    var
+        ExpenseAgentSetup: Record "Expense Agent Setup";
+    begin
+        if ExpenseAgentSetup.Get() then begin
+            ExpenseAgentSetup."JIT Provisioning Completed" := Completed;
+            ExpenseAgentSetup.Modify(true);
+        end;
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Company-Initialize", 'OnCompanyInitialize', '', false, false)]
+    local procedure OnCompanyInitialize()
+    begin
+        InitializeExpenseAgentSetup();
+    end;
+}

--- src/AIContextBuilder.Codeunit.al
+++ src/AIContextBuilder.Codeunit.al
+codeunit 57500 "AI Context Builder"
+{
+    Access = Public;
+
+    procedure BuildTaskExecutionContext(AgentTaskId: Guid): Text
+    var
+        AgentTask: Record "Agent Task";
+        User: Record User;
+        ContextText: Text;
