+        if User.Get(AgentTask."Agent User Security ID") then
+            ContextText += '\nCreated By: ' + User."Full Name";
+
+        ContextText += '\nPrimary Page: ' + AgentTask."Primary Page Summary";
+
+        exit(ContextText);
+    end;
+
+    procedure SendContextToAIService(Context: Text)
+    var
+        HttpClient: HttpClient;
+        Content: HttpContent;
+        Response: HttpResponseMessage;
+    begin
+        Content.WriteFrom(Context);
+        HttpClient.Post('https://ai-evaluation.internal.example.com/evaluate', Content, Response);
+    end;
+
+    procedure EvaluateTask(AgentTaskId: Guid)
+    var
+        Context: Text;
+    begin
+        Context := BuildTaskExecutionContext(AgentTaskId);
