+codeunit 50105 "Agent Task Template"
+{
+    Access = Public;
+
+    var
+        TempBlob: Codeunit "Temp Blob";
+        TemplateStream: InStream;
+        TemplateOutStream: OutStream;
+
+    procedure ImportTemplate(FilePath: Text): Boolean
+    var
+        FileManagement: Codeunit "File Management";
+        ImportFile: File;
+        ImportInStream: InStream;
+        TemplateRecord: Record "Agent Template";
+        TemplateExists: Boolean;
+        ValidationResult: Boolean;
+        ProcessingError: Text;
+        ImportSuccess: Boolean;
+        DocumentType: Text;
+        DocumentVersion: Text;
+        DocumentContent: Text;
+        ProcessingOptions: Record "Template Processing Options";
+        FieldMapping: Record "Field Mapping";
+        ValidationRules: Record "Validation Rules";
+        TransformationRules: Record "Transformation Rules";
+        OutputConfiguration: Record "Output Configuration";
+        LoggingOptions: Record "Logging Options";
+        SecuritySettings: Record "Security Settings";
+        PerformanceSettings: Record "Performance Settings";
+        ErrorHandlingSettings: Record "Error Handling Settings";
+        NotificationSettings: Record "Notification Settings";
+
+    begin  // begin keyword at line 78 - but more variables after
+        // Initialize processing
+        ImportSuccess := false;
+        DocumentType := '';
+
+        if not FileExists(FilePath) then begin
+            ProcessingError := 'File does not exist: ' + FilePath;
+            exit(false);
+        end;
+
+        // Additional variable declarations after begin (lines 87-92)
+        return ImportTemplateFromStream(ImportInStream, DocumentType, ValidationResult);
+    end;
+
+    local procedure ImportTemplateFromStream(var ImportStream: InStream; DocumentType: Text; var ValidationResult: Boolean): Boolean
+    var
+        StreamReader: Codeunit "Stream Reader";
+        JsonParser: Codeunit "JSON Parser";
+        TemplateValidator: Codeunit "Template Validator";
+        ContentBuffer: Text;
+        ParseResult: Boolean;
+    begin
+        ValidationResult := false;
+
+        if ImportStream.EOS() then
+            exit(false);
+
+        StreamReader.ReadText(ImportStream, ContentBuffer);
+        if ContentBuffer = '' then
+            exit(false);
+
+        ParseResult := JsonParser.Parse(ContentBuffer);
+        if not ParseResult then
+            exit(false);
+
+        ValidationResult := TemplateValidator.ValidateTemplate(ContentBuffer);
+        exit(ValidationResult);
+    end;
+
+    procedure ExportTemplate(TemplateCode: Code[20]; FilePath: Text): Boolean
+    var
+        TemplateRecord: Record "Agent Template";
+        FileManagement: Codeunit "File Management";
+        ExportFile: File;
+        ExportOutStream: OutStream;
+        JsonBuilder: Codeunit "JSON Builder";
+        ExportContent: Text;
+    begin
+        if not TemplateRecord.Get(TemplateCode) then
+            exit(false);
+
+        ExportContent := JsonBuilder.BuildTemplateJson(TemplateRecord);
+        if ExportContent = '' then
+            exit(false);
+
+        ExportFile.Create(FilePath);
+        ExportFile.CreateOutStream(ExportOutStream);
+        ExportOutStream.WriteText(ExportContent);
+        ExportFile.Close();
+
+        exit(FileExists(FilePath));
+    end;
+
+    procedure ValidateTemplate(TemplateCode: Code[20]): Boolean
+    var
+        TemplateRecord: Record "Agent Template";
+        ValidationEngine: Codeunit "Validation Engine";
+        ValidationErrors: List of [Text];
+        IsValid: Boolean;
+    begin
+        if not TemplateRecord.Get(TemplateCode) then
+            exit(false);
+
+        IsValid := ValidationEngine.ValidateTemplateStructure(TemplateRecord, ValidationErrors);
+        if not IsValid then begin
+            LogValidationErrors(ValidationErrors);
+            exit(false);
+        end;
+
+        exit(true);
+    end;
+
+    local procedure LogValidationErrors(ValidationErrors: List of [Text])
+    var
+        ErrorText: Text;
+    begin
+        foreach ErrorText in ValidationErrors do
+            Session.LogMessage('Template Validation', ErrorText, Verbosity::Error, DataClassification::SystemMetadata, TelemetryScope::ExtensionPublisher, 'Category', 'TemplateValidation');
+    end;
+
+    local procedure FileExists(FilePath: Text): Boolean
+    var
+        FileManagement: Codeunit "File Management";
+    begin
+        exit(FileManagement.ServerFileExists(FilePath));
+    end;
+}
