+++ src/PayablesAgent.Codeunit.al
+codeunit 50106 "Payables Agent"
+{
+    Access = Public;
+
+    var
+        PayablesSetup: Record "Payables Agent Setup";
+        TelemetryManager: Codeunit "Telemetry Management";
+        MLLMConnector: Codeunit "MLLM Connector";
+
+    procedure ProcessPendingPayables(): Boolean
+    var
+        PendingInvoices: Record "Purchase Header";
+        ProcessingResult: Boolean;
+        ProcessedCount: Integer;
+        ErrorCount: Integer;
+        StartTime: DateTime;
+        EndTime: DateTime;
+        ProcessingLog: Record "Agent Processing Log";
+    begin
+        if not GetSetup() then
+            exit(false);
+
+        if not PayablesSetup."Enable Agent Processing" then
+            exit(true);
+
+        StartTime := CurrentDateTime();
+        ProcessingResult := true;
+        ProcessedCount := 0;
+        ErrorCount := 0;
+
+        PendingInvoices.SetRange("Document Type", PendingInvoices."Document Type"::Invoice);
+        PendingInvoices.SetRange(Status, PendingInvoices.Status::Open);
+        PendingInvoices.SetFilter("Agent Processing Status", '%1|%2', 'Pending', 'Retry');
+
+        if PendingInvoices.FindSet() then
+            repeat
+                if ProcessSingleInvoice(PendingInvoices) then
+                    ProcessedCount += 1
+                else
+                    ErrorCount += 1;
+            until PendingInvoices.Next() = 0;
+
+        EndTime := CurrentDateTime();
+        ProcessingResult := (ErrorCount = 0);
+
+        LogProcessingResults(StartTime, EndTime, ProcessedCount, ErrorCount);
+        exit(ProcessingResult);
+    end;
+
+    procedure ProcessSingleInvoice(var PurchaseHeader: Record "Purchase Header"): Boolean
+    var
+        ProcessingResult: Boolean;
+        ValidationResult: Boolean;
+        PostingResult: Boolean;
+        MLLMAnalysis: Text;
+        ErrorMessage: Text;
+        RetryAttempts: Integer;
+    begin
+        ProcessingResult := false;
+
+        // Validate the invoice
+        ValidationResult := ValidateInvoice(PurchaseHeader, ErrorMessage);
+        if not ValidationResult then begin
+            LogProcessingError(PurchaseHeader."No.", ErrorMessage);
+            exit(false);
+        end;
+
+        // Analyze with MLLM if enabled
+        if PayablesSetup."Use MLLM Processing" then begin
+            MLLMAnalysis := AnalyzeInvoiceWithMLLM(PurchaseHeader);
+            if MLLMAnalysis <> '' then
+                ApplyMLLMRecommendations(PurchaseHeader, MLLMAnalysis);
+        end;
+
+        // Determine if automatic posting should be performed
+        if ShouldAutoPost(PurchaseHeader) then begin
+            begin  // BEGIN..END for single statement - line 235
+                if PayablesSetup."Auto-Post Journals" then  // IF statement makes it compound - line 237
+                    PostingResult := PostInvoice(PurchaseHeader, ErrorMessage);
+            end
+            else begin
+                // Mark for manual review
+                MarkForManualReview(PurchaseHeader);
+                PostingResult := true;
+            end;
+
+            if PostingResult then begin
+                UpdateProcessingStatus(PurchaseHeader, 'Completed');
+                ProcessingResult := true;
+            end else begin
+                RetryAttempts := GetRetryAttempts(PurchaseHeader."No.");
+                if RetryAttempts < PayablesSetup."Max Retry Attempts" then begin
+                    UpdateProcessingStatus(PurchaseHeader, 'Retry');
+                    IncrementRetryCount(PurchaseHeader."No.");
+                end else begin
+                    UpdateProcessingStatus(PurchaseHeader, 'Failed');
+                    LogProcessingError(PurchaseHeader."No.", ErrorMessage);
+                end;
+            end;
+
+            exit(ProcessingResult);
+        end;
+
+        local procedure ValidateInvoice(var PurchaseHeader: Record "Purchase Header"; var ErrorMessage: Text): Boolean
+    var
+        PurchaseLine: Record "Purchase Line";
+        Vendor: Record Vendor;
+        ValidationEngine: Codeunit "Purchase Validation";
+        IsValid: Boolean;
+    begin
+        IsValid := true;
+        ErrorMessage := '';
+
+        // Basic header validation
+        if not Vendor.Get(PurchaseHeader."Buy-from Vendor No.") then begin
+            ErrorMessage := 'Vendor does not exist: ' + PurchaseHeader."Buy-from Vendor No.";
+            exit(false);
+        end;
+
+        // Validate lines exist
+        PurchaseLine.SetRange("Document Type", PurchaseHeader."Document Type");
+        PurchaseLine.SetRange("Document No.", PurchaseHeader."No.");
+        if PurchaseLine.IsEmpty() then begin
+            ErrorMessage := 'No purchase lines found for document: ' + PurchaseHeader."No.";
+            exit(false);
+        end;
+
+        // Additional validations
+        IsValid := ValidationEngine.ValidatePurchaseDocument(PurchaseHeader, ErrorMessage);
+        exit(IsValid);
+    end;
+
+    local procedure AnalyzeInvoiceWithMLLM(var PurchaseHeader: Record "Purchase Header"): Text
+    var
+        AnalysisRequest: Text;
+        AnalysisResponse: Text;
+        InvoiceData: Text;
+    begin
+        InvoiceData := BuildInvoiceDataForAnalysis(PurchaseHeader);
+        AnalysisRequest := BuildMLLMAnalysisRequest(InvoiceData);
+
+        if MLLMConnector.SendAnalysisRequest(AnalysisRequest, AnalysisResponse) then
+            exit(AnalysisResponse)
+        else
+            exit('');
+    end;
+
+    local procedure GetSetup(): Boolean
+    begin
+        if not PayablesSetup.Get('') then begin
+            PayablesSetup.InitializeSetup();
+            PayablesSetup.Get('');
+        end;
+        exit(true);
+    end;
+
+    local procedure LogProcessingResults(StartTime: DateTime; EndTime: DateTime; ProcessedCount: Integer; ErrorCount: Integer)
+    var
+        ProcessingLog: Record "Agent Processing Log";
+        Duration: Duration;
+    begin
+        Duration := EndTime - StartTime;
+
+        ProcessingLog.Init();
+        ProcessingLog."Entry No." := GetNextLogEntryNo();
+        ProcessingLog."Processing Date" := DT2Date(StartTime);
+        ProcessingLog."Start Time" := DT2Time(StartTime);
+        ProcessingLog."End Time" := DT2Time(EndTime);
+        ProcessingLog."Duration (ms)" := Duration;
+        ProcessingLog."Processed Count" := ProcessedCount;
+        ProcessingLog."Error Count" := ErrorCount;
+        ProcessingLog."Agent Type" := 'Payables';
+        ProcessingLog.Insert(true);
+    end;
+
+    local procedure GetNextLogEntryNo(): Integer
+    var
+        ProcessingLog: Record "Agent Processing Log";
+    begin
+        ProcessingLog.SetCurrentKey("Entry No.");
+        if ProcessingLog.FindLast() then
+            exit(ProcessingLog."Entry No." + 1)
+        else
+            exit(1);
+    end;
+
+    // Additional helper procedures would be implemented here
+    local procedure PostInvoice(var PurchaseHeader: Record "Purchase Header"; var ErrorMessage: Text): Boolean
+    begin
+        exit(true); // Simplified implementation
+    end;
+
+    local procedure ShouldAutoPost(var PurchaseHeader: Record "Purchase Header"): Boolean
+    begin
+        exit(PayablesSetup."Auto-Post Journals");
+    end;
+
+    local procedure MarkForManualReview(var PurchaseHeader: Record "Purchase Header")
+    begin
+        // Implementation for marking invoice for manual review
+    end;
+
+    local procedure UpdateProcessingStatus(var PurchaseHeader: Record "Purchase Header"; NewStatus: Text)
