+        IsLCY: Boolean;
+        GLSetupRead: Boolean;
+    begin
+        ToleranceAmount := 0;
+
+        if not CustLedgerEntry.Get(CustLedgerEntry."Entry No.") then
+            exit(false);
+
+        if not Customer.Get(CustLedgerEntry."Customer No.") then
+            exit(false);
+
+        // Get setup information
+        if not GLSetupRead then begin
+            GeneralLedgerSetup.Get();
+            GLSetupRead := true;
+        end;
+
+        // Calculate remaining amount
+        CustLedgerEntry.CalcFields("Remaining Amount", "Remaining Amt. (LCY)");
+        RemainingAmount := CustLedgerEntry."Remaining Amount";
+
+        // Get currency information
+        CurrencyCode := CustLedgerEntry."Currency Code";
+        if CurrencyCode = '' then begin
+            CurrencyCode := GeneralLedgerSetup."LCY Code";
+            IsLCY := true;
+        end else
+            IsLCY := false;
+
+        // Get currency precision
+        if IsLCY then
+            CurrencyPrecision := GeneralLedgerSetup."Amount Rounding Precision"
+        else begin
+            if not GetCurrencyPrecision(CurrencyCode, CurrencyPrecision) then
+                CurrencyPrecision := 0.01;
+        end;
+
+        // Calculate payment tolerance based on setup
+        if Customer."Payment Tolerance %" <> 0 then begin
+            MaxTolerancePercent := Customer."Payment Tolerance %";
+            MaxToleranceAmount := Customer."Max. Payment Tolerance";
+        end else begin
+            MaxTolerancePercent := GeneralLedgerSetup."Payment Tolerance %";
+            MaxToleranceAmount := GeneralLedgerSetup."Max. Payment Tolerance";
+        end;
+
+        // Calculate base amount for tolerance calculation
+        CalculationBase := Abs(RemainingAmount);
+
+        // Calculate tolerance amount
+        if MaxTolerancePercent <> 0 then
+            ToleranceAmount := Round(CalculationBase * MaxTolerancePercent / 100, CurrencyPrecision);
+
+        // Apply maximum tolerance limit
+        if (MaxToleranceAmount > 0) and (ToleranceAmount > MaxToleranceAmount) then
+            ToleranceAmount := MaxToleranceAmount;
+
+        // Validate tolerance against payment amount difference
+        AmountToApply := Abs(PaymentAmount);
+        AppliedAmount := Abs(RemainingAmount);
+
+        if AmountToApply < AppliedAmount then begin
+            PmtToleranceAmount := AppliedAmount - AmountToApply;
+            IsWithinTolerance := (PmtToleranceAmount <= ToleranceAmount);
+        end else if AmountToApply > AppliedAmount then begin
+            PmtToleranceAmount := AmountToApply - AppliedAmount;
+            IsWithinTolerance := (PmtToleranceAmount <= ToleranceAmount);
+        end else begin
+            PmtToleranceAmount := 0;
+            IsWithinTolerance := true;
+        end;
+
+        // Final validation with excessive indentation issue on line 1609
+        if IsWithinTolerance then begin
+            if CustLedgerEntry."Document Type" = CustLedgerEntry."Document Type"::Invoice then begin
+                if (PmtToleranceAmount > 0) and (ToleranceAmount > 0) then  // Excessive indentation - line 1609
+                    ToleranceAmount := PmtToleranceAmount
+                else
+                    ToleranceAmount := 0;
+            end;
+        end else
+            ToleranceAmount := 0;
+
+        exit(IsWithinTolerance);
+    end;
+
+    procedure ValidatePaymentTolerance(DocumentAmount: Decimal; PaymentAmount: Decimal; CustomerNo: Code[20]): Boolean
+    var
+        Customer: Record Customer;
+        ToleranceAmount: Decimal;
+        AmountDifference: Decimal;
+        IsValid: Boolean;
+    begin
+        if not Customer.Get(CustomerNo) then
+            exit(false);
+
+        AmountDifference := Abs(DocumentAmount - PaymentAmount);
+
+        if AmountDifference = 0 then
+            exit(true);
+
+        ToleranceAmount := CalculateToleranceAmount(DocumentAmount, Customer);
+        IsValid := (AmountDifference <= ToleranceAmount);
+
+        exit(IsValid);
+    end;
+
+    local procedure CalculateToleranceAmount(BaseAmount: Decimal; Customer: Record Customer): Decimal
+    var
+        TolerancePercent: Decimal;
+        MaxTolerance: Decimal;
+        CalculatedTolerance: Decimal;
+    begin
+        if Customer."Payment Tolerance %" <> 0 then begin
+            TolerancePercent := Customer."Payment Tolerance %";
+            MaxTolerance := Customer."Max. Payment Tolerance";
+        end else begin
+            if not GeneralLedgerSetup.Get() then
+                exit(0);
+            TolerancePercent := GeneralLedgerSetup."Payment Tolerance %";
+            MaxTolerance := GeneralLedgerSetup."Max. Payment Tolerance";
+        end;
+
+        if TolerancePercent <> 0 then
+            CalculatedTolerance := Abs(BaseAmount) * TolerancePercent / 100;
+
+        if (MaxTolerance > 0) and (CalculatedTolerance > MaxTolerance) then
+            CalculatedTolerance := MaxTolerance;
+
+        exit(CalculatedTolerance);
+    end;
+
+    local procedure GetCurrencyPrecision(CurrencyCode: Code[10]; var Precision: Decimal): Boolean
+    var
+        Currency: Record Currency;
+    begin
+        if Currency.Get(CurrencyCode) then begin
+            Precision := Currency."Amount Rounding Precision";
+            exit(true);
+        end else begin
+            Precision := 0.01;
+            exit(false);
+        end;
+    end;
+
+    procedure PostToleranceEntry(var CustLedgerEntry: Record "Cust. Ledger Entry"; ToleranceAmount: Decimal; PostingDate: Date): Boolean
+    var
+        GenJournalLine: Record "Gen. Journal Line";
+        GenJournalPostLine: Codeunit "Gen. Jnl.-Post Line";
+        Customer: Record Customer;
+        PaymentToleranceAccount: Code[20];
+        PostingResult: Boolean;
+    begin
+        if ToleranceAmount = 0 then
+            exit(true);
+
+        if not Customer.Get(CustLedgerEntry."Customer No.") then
+            exit(false);
+
+        // Get payment tolerance account
+        if not GeneralLedgerSetup.Get() then
+            exit(false);
+
+        PaymentToleranceAccount := GeneralLedgerSetup."Payment Tolerance Account";
+        if PaymentToleranceAccount = '' then
+            exit(false);
+
+        // Create journal line for tolerance entry
+        GenJournalLine.Init();
+        GenJournalLine."Document Type" := GenJournalLine."Document Type"::" ";
+        GenJournalLine."Document No." := CustLedgerEntry."Document No." + '-TOL';
+        GenJournalLine."Posting Date" := PostingDate;
+        GenJournalLine."Account Type" := GenJournalLine."Account Type"::"G/L Account";
+        GenJournalLine."Account No." := PaymentToleranceAccount;
+        GenJournalLine.Amount := ToleranceAmount;
+        GenJournalLine."Currency Code" := CustLedgerEntry."Currency Code";
+        GenJournalLine.Description := 'Payment Tolerance for ' + CustLedgerEntry."Document No.";
+
+        // Post the journal line
+        PostingResult := GenJournalPostLine.RunWithCheck(GenJournalLine);
+
+        exit(PostingResult);
+    end;
+}
