--- src/EnumConversionHelper.Codeunit.al
+++ src/EnumConversionHelper.Codeunit.al
+codeunit 50101 EnumConversionHelper
+{
+    procedure ConvertPaymentMethodToEnum(PaymentMethod: Code[20]): Enum "Payment Method Type"
+    begin
+        // This LOOKS like a risky enum conversion because we're converting from
+        // a flexible Code field to a constrained enum, but it's actually SAFE because:
+        // 1. We have comprehensive fallback handling for all cases
+        // 2. The conversion maintains backward compatibility
+        // 3. Unknown values are gracefully handled, not lost
+        // 4. This is an additive change that extends functionality
+
+        case PaymentMethod of
+            'CASH':
+                exit("Payment Method Type"::Cash);
+            'CHECK', 'CHEQUE':
+                exit("Payment Method Type"::Check);
+            'CARD', 'CREDIT':
+                exit("Payment Method Type"::"Credit Card");
+            'BANK', 'TRANSFER', 'WIRE':
+                exit("Payment Method Type"::"Bank Transfer");
+            'ELECTRONIC', 'EFT', 'ACH':
+                exit("Payment Method Type"::Electronic);
+            else begin
+                // SAFE: Unknown payment methods are preserved via Other category
+                // This prevents data loss and maintains system stability
+                // Legacy integrations continue to work without modification
+                exit("Payment Method Type"::Other);
+            end;
+        end;
+    end;
+
+    procedure GetLegacyPaymentCode(PaymentMethodType: Enum "Payment Method Type"): Code[20]
+    begin
+        // This reverse conversion ensures complete backward compatibility
+        // Old reports and integrations can still access the original codes
+        case PaymentMethodType of
+            "Payment Method Type"::Cash:
+                exit('CASH');
+            "Payment Method Type"::Check:
+                exit('CHECK');
+            "Payment Method Type"::"Credit Card":
+                exit('CARD');
+            "Payment Method Type"::"Bank Transfer":
+                exit('BANK');
+            "Payment Method Type"::Electronic:
+                exit('ELECTRONIC');
+            "Payment Method Type"::Other:
+                exit('OTHER');
+            else
+                Error('Unknown payment method type %1.', PaymentMethodType);
+        end;
+    end;
+}
