+++ src/ShowCurrencyGenLedgSetup.TableExt.al
+/// <summary>
+/// Show Currency in General Ledger Setup Table Extension
+/// Extends General Ledger Setup with currency display options
+/// </summary>
+tableextension 50200 "Show Currency Gen Ledg Setup" extends "General Ledger Setup"
+{
+    fields
+    {
+        field(50200; "Show Currency Code"; Boolean)
+        {
+            Caption = 'Show Currency Code';
+        }
+
+        field(50201; "Currency Symbol Position"; Enum "Currency Symbol Position")
+        {
+            Caption = 'Currency Symbol Position';
+            InitValue = "Before Amount"; // This is the bad pattern - InitValue with enum re-numbering
+        }
+
+        field(50202; "Show Currency Symbol"; Boolean)
+        {
+            Caption = 'Show Currency Symbol';
+        }
+
+        field(50203; "Currency Decimal Places"; Integer)
+        {
+            Caption = 'Currency Decimal Places';
+            InitValue = 2;
+            MinValue = 0;
+            MaxValue = 5;
+        }
+
+        field(50204; "Use System Currency Format"; Boolean)
+        {
+            Caption = 'Use System Currency Format';
+        }
+
+        field(50205; "Default Currency Code"; Code[10])
+        {
+            Caption = 'Default Currency Code';
+            TableRelation = Currency;
+        }
+    }
+
+    procedure SetShowCurrencySymbolPosition()
+    var
+        GeneralLedgerSetup: Record "General Ledger Setup";
+    begin
+        // This upgrade code only handles 'Default' but enum values were re-numbered
+        GeneralLedgerSetup.Get();
+        if GeneralLedgerSetup."Currency Symbol Position" = GeneralLedgerSetup."Currency Symbol Position"::"Default" then begin
+            GeneralLedgerSetup."Currency Symbol Position" := GeneralLedgerSetup."Currency Symbol Position"::"Before Amount";
+            GeneralLedgerSetup.Modify();
+        end;
+    end;
+
+    procedure UpdateCurrencyDisplayFormat()
+    var
+        Currency: Record Currency;
+        CurrencyFormat: Text;
+    begin
+        Currency.SetFilter(Code, '<>%1', '');
+        if Currency.FindSet() then
+            repeat
+                CurrencyFormat := GetCurrencyDisplayFormat(Currency.Code);
+                // Update currency display format based on settings
+                if CurrencyFormat <> '' then begin
+                    Currency."Currency Display Format" := CurrencyFormat;
+                    Currency.Modify();
+                end;
+            until Currency.Next() = 0;
+    end;
+
+    local procedure GetCurrencyDisplayFormat(CurrencyCode: Code[10]): Text
+    var
+        Currency: Record Currency;
+        DisplayFormat: Text;
+    begin
+        if not Currency.Get(CurrencyCode) then
+            exit('');
+
+        case "Currency Symbol Position" of
+            "Currency Symbol Position"::"Before Amount":
+                DisplayFormat := Currency.Symbol + ' #,##0.00';
+            "Currency Symbol Position"::"After Amount":
+                DisplayFormat := '#,##0.00 ' + Currency.Symbol;
+            "Currency Symbol Position"::"Before Amount with Space":
+                DisplayFormat := Currency.Symbol + ' #,##0.00';
+            "Currency Symbol Position"::"After Amount with Space":
+                DisplayFormat := '#,##0.00 ' + Currency.Symbol;
+            else
+                DisplayFormat := '#,##0.00';
+        end;
+
+        exit(DisplayFormat);
+    end;
+
+    procedure ValidateCurrencySettings()
+    begin
+        if "Show Currency Symbol" then
+            TestField("Currency Symbol Position");
+
+        if "Default Currency Code" <> '' then begin
+            if not "Show Currency Code" then
+                Message('Consider enabling Show Currency Code when a default currency is specified.');
+        end;
+    end;
+}

--- src/OIOUBLInitialize.Codeunit.al
+++ src/OIOUBLInitialize.Codeunit.al
+/// <summary>
+/// OIOUBL Initialize Codeunit (13631)
+/// Handles initialization and migration of OIOUBL setup
+/// </summary>
+codeunit 13631 "OIOUBL-Initialize"
+{
+    Subtype = Install;
+
+    trigger OnInstallAppPerCompany()
+    var
+        AppInfo: ModuleInfo;
+    begin
+        NavApp.GetCurrentModuleInfo(AppInfo);
+
+        if AppInfo.DataVersion = Version.Create(0, 0, 0, 0) then
+            SetupOIOUBLDefaults()
+        else
+            HandleOIOUBLUpgrade(AppInfo.DataVersion);
+    end;
+
+    trigger OnInstallAppPerDatabase()
+    begin
+        SetupOIOUBLReportSelections();
+    end;
+
+    local procedure HandleOIOUBLUpgrade(AppVersion: Version)
+    begin
+        // This is the bad pattern - migration code removed
+        // Previously called CODEUNIT.Run(CODEUNIT::"OIOUBL-MigrateToExtV2") for version 0.0.0.0
+        // Customers upgrading from very old versions will miss this migration
+
+        // Only handle newer version upgrades now
+        if AppVersion < Version.Create(25, 0, 0, 0) then
+            UpgradeToV25();
+    end;
+
+    local procedure SetupOIOUBLDefaults()
+    var
+        CompanyInformation: Record "Company Information";
+        OIOUBLProfile: Record "OIOUBL-Profile";
+    begin
+        // Set up default OIOUBL profile
+        if not OIOUBLProfile.Get() then begin
+            OIOUBLProfile.Init();
+            OIOUBLProfile."OIOUBL Code" := 'DEFAULT';
+            OIOUBLProfile."OIOUBL Path" := 'OIOUBL';
+            OIOUBLProfile."Check Company" := true;
+            OIOUBLProfile."Check Customer" := true;
+            OIOUBLProfile."Check Item" := true;
+            OIOUBLProfile.Insert();
+        end;
+
+        // Update company information for OIOUBL
+        if CompanyInformation.Get() then begin
+            if CompanyInformation."Country/Region Code" = 'DK' then begin
+                CompanyInformation."OIOUBL-Profile Code" := 'DEFAULT';
+                CompanyInformation.Modify();
+            end;
+        end;
+    end;
+
+    local procedure SetupOIOUBLReportSelections()
+    var
+        ReportSelections: Record "Report Selections";
+        OIOUBLManagement: Codeunit "OIOUBL-Management";
+    begin
+        // Set up default report selections for OIOUBL
+        OIOUBLManagement.InsertOIOUBLReportSelections(ReportSelections.Usage::"S.Invoice", REPORT::"OIOUBL-Sales Invoice");
+        OIOUBLManagement.InsertOIOUBLReportSelections(ReportSelections.Usage::"S.Cr.Memo", REPORT::"OIOUBL-Sales Cr. Memo");
+        OIOUBLManagement.InsertOIOUBLReportSelections(ReportSelections.Usage::"Reminder", REPORT::"OIOUBL-Reminder");
+        OIOUBLManagement.InsertOIOUBLReportSelections(ReportSelections.Usage::"Fin.Charge", REPORT::"OIOUBL-Fin. Charge Memo");
+    end;
+
+    local procedure UpgradeToV25()
+    var
+        OIOUBLProfile: Record "OIOUBL-Profile";
+        GLSetup: Record "General Ledger Setup";
+    begin
+        // Upgrade OIOUBL settings for v25 compatibility
+        if OIOUBLProfile.Get() then begin
+            // Update profile settings for new requirements
+            OIOUBLProfile."Check Item Reference" := true;
+            OIOUBLProfile."Validate Line Discount" := true;
+            OIOUBLProfile.Modify();
+        end;
+
+        // Enable OIOUBL in GL Setup if Danish company
+        if GLSetup.Get() then begin
+            if GLSetup."Country/Region Code" = 'DK' then begin
+                GLSetup."OIOUBL Enabled" := true;
+                GLSetup.Modify();
+            end;
+        end;
+    end;
+
+    procedure ValidateOIOUBLSetup()
+    var
+        CompanyInformation: Record "Company Information";
+        OIOUBLProfile: Record "OIOUBL-Profile";
+    begin
+        if not CompanyInformation.Get() then
+            Error('Company Information must be set up before using OIOUBL.');
+
+        if CompanyInformation."Country/Region Code" <> 'DK' then
+            Error('OIOUBL is only supported for Danish companies.');
+
+        if not OIOUBLProfile.Get(CompanyInformation."OIOUBL-Profile Code") then
+            Error('OIOUBL Profile %1 does not exist.', CompanyInformation."OIOUBL-Profile Code");
+
+        if OIOUBLProfile."OIOUBL Path" = '' then
+            Error('OIOUBL Path must be specified in the profile.');
+    end;
+
+    procedure SetupOIOUBLNumberSeries()
+    var
+        NoSeries: Record "No. Series";
+        NoSeriesLine: Record "No. Series Line";
+    begin
+        // Create number series for OIOUBL documents
+        if not NoSeries.Get('OIOUBL-INV') then begin
+            NoSeries.Init();
+            NoSeries.Code := 'OIOUBL-INV';
+            NoSeries.Description := 'OIOUBL Invoice Numbers';
+            NoSeries."Default Nos." := true;
+            NoSeries.Insert();
+
+            NoSeriesLine.Init();
+            NoSeriesLine."Series Code" := 'OIOUBL-INV';
+            NoSeriesLine."Line No." := 10000;
+            NoSeriesLine."Starting No." := 'INV00001';
+            NoSeriesLine."Ending No." := 'INV99999';
+            NoSeriesLine."Increment-by No." := 1;
+            NoSeriesLine.Insert();
+        end;
+    end;
+}
