+
+    procedure CalculateTotalWHTAmount()
+    var
+        PurchInvLine: Record "Purch. Inv. Line";
+        TotalWHTAmount: Decimal;
+        TotalWHTAmountLCY: Decimal;
+    begin
+        PurchInvLine.SetRange("Document No.", "No.");
+        PurchInvLine.SetFilter("WHT Amount", '<>0');
+        if PurchInvLine.FindSet() then
+            repeat
+                TotalWHTAmount += PurchInvLine."WHT Amount";
+                TotalWHTAmountLCY += PurchInvLine."WHT Amount (LCY)";
+            until PurchInvLine.Next() = 0;
+
+        "Total WHT Amount" := TotalWHTAmount;
+        "Total WHT Amount (LCY)" := TotalWHTAmountLCY;
+        Modify();
+    end;
+
+    procedure PrintWHTCertificate()
+    var
+        WHTCertificate: Record "WHT Certificate";
+        WHTCertificateReport: Report "WHT Certificate";
+    begin
+        if "WHT Certificate No." = '' then
+            Error('WHT Certificate No. must be specified to print certificate.');
+
+        WHTCertificate.SetRange("Certificate No.", "WHT Certificate No.");
+        WHTCertificateReport.SetTableView(WHTCertificate);
+        WHTCertificateReport.Run();
+    end;
+
+    procedure ValidateWHTPostingGroups()
+    var
+        WHTPostingSetup: Record "WHT Posting Setup";
+    begin
+        if ("WHT Business Posting Group" <> '') or ("WHT Product Posting Group" <> '') then begin
+            TestField("WHT Business Posting Group");
+            TestField("WHT Product Posting Group");
+
+            if not WHTPostingSetup.Get("WHT Business Posting Group", "WHT Product Posting Group") then
+                Error('WHT Posting Setup %1,%2 does not exist.', "WHT Business Posting Group", "WHT Product Posting Group");
+        end;
+    end;
+
+    procedure GetWHTEntries(var WHTEntry: Record "WHT Entry")
+    begin
+        WHTEntry.SetCurrentKey("Document Type", "Document No.");
+        WHTEntry.SetRange("Document Type", WHTEntry."Document Type"::Invoice);
+        WHTEntry.SetRange("Document No.", "No.");
+    end;
+
+    procedure HasWHTEntries(): Boolean
+    var
+        WHTEntry: Record "WHT Entry";
+    begin
+        GetWHTEntries(WHTEntry);
+        exit(not WHTEntry.IsEmpty);
+    end;
+
+    procedure GenerateWHTCertificate()
+    var
+        WHTCertificate: Record "WHT Certificate";
+        WHTManagement: Codeunit "WHT Management";
+    begin
+        if "WHT Certificate No." <> '' then
+            Error('WHT Certificate already exists for this document.');
+
+        if "Total WHT Amount" = 0 then
+            Error('Cannot generate WHT Certificate when WHT Amount is zero.');
+
+        "WHT Certificate No." := WHTManagement.CreateWHTCertificate(Rec);
+        Modify();
+    end;
+}

